import pg from "pg";
import crypto from "crypto";
const Pool = pg.Pool;
const pool = new Pool({ connectionString: process.env.PROD_DATABASE_URL || process.env.DATABASE_URL });
function hash(s: string): string { return crypto.createHash("md5").update(s.toLowerCase().trim()).digest("hex"); }
function rn(e:string,b:string,d:number,s:string,o:string[],c:number,r:string) {
  return {tier:"rn",exam:e,stem:s,options:o,correct:c,rationale:r,diff:d,bs:b};
}
function np(e:string,b:string,d:number,s:string,o:string[],c:number,r:string) {
  return {tier:"np",exam:e,stem:s,options:o,correct:c,rationale:r,diff:d,bs:b};
}

const QS = [
  // === RN (150 questions) ===
  rn("NCLEX-RN","Cardiovascular",3,"A client with chronic stable angina is prescribed ranolazine as add-on therapy. The nurse should teach that this medication works by:",["Dilating coronary arteries","Inhibiting late sodium current to reduce calcium overload and improve diastolic relaxation","Blocking beta receptors","Inhibiting platelet aggregation"],1,"Ranolazine inhibits late sodium current (INaL), reducing intracellular sodium and calcium overload, which improves myocardial relaxation and reduces ischemia without affecting heart rate or blood pressure. Add-on therapy for angina refractory to nitrates, beta-blockers, and CCBs. May prolong QTc."),
  rn("NCLEX-RN","Cardiovascular",3,"A client with heart failure and reduced ejection fraction is started on sacubitril/valsartan. The nurse should ensure:",["The client is currently taking an ACE inhibitor","There is a 36-hour washout period after stopping the ACE inhibitor before starting sacubitril/valsartan","The client takes both medications simultaneously","No washout period is needed"],1,"Sacubitril/valsartan (Entresto) combines a neprilysin inhibitor with an ARB. ACEi must be stopped 36 hours before starting to prevent angioedema risk (neprilysin and ACE both degrade bradykinin). PARADIGM-HF trial showed 20% reduction in cardiovascular death and HF hospitalization vs. enalapril."),
  rn("NCLEX-RN","Cardiovascular",3,"A client with symptomatic bradycardia and third-degree AV block should have the nurse prepare for:",["Observation only","Temporary transcutaneous pacing followed by permanent pacemaker placement","Cardioversion","Defibrillation"],1,"Third-degree (complete) AV block: no conduction between atria and ventricles. Symptomatic bradycardia: atropine (may not work in complete block), transcutaneous pacing as a bridge, then permanent pacemaker. Causes: MI (inferior), medications (beta-blockers, CCBs, digoxin), and degenerative conduction system disease."),
  rn("RN-CAT","Cardiovascular",4,"A client with acute type A aortic dissection should have the nurse prepare for:",["Medical management alone","Emergency surgical repair as type A dissection has high mortality without surgery","Outpatient follow-up","Endovascular stenting only"],1,"Stanford Type A (ascending aorta): surgical emergency. Type B (descending only): medical management unless complicated. Type A mortality: 1-2% per hour without surgery. Management: IV beta-blocker first (target HR < 60, SBP 100-120), then vasodilators if needed. Pain management. Emergency surgery for repair/replacement."),
  rn("NCLEX-RN","Cardiovascular",3,"A client post-cardiac catheterization via femoral approach should have the nurse monitor the access site for:",["Mild bruising only","Hematoma formation, bleeding, retroperitoneal hemorrhage signs (back pain, hypotension), and distal pulse assessment","Only distal pulse checks","No monitoring needed after hemostasis"],1,"Post-femoral catheterization: monitor access site every 15 minutes x4, then every 30 minutes x2, then hourly. Check: active bleeding, expanding hematoma, bruit (pseudoaneurysm), distal pulses (dorsalis pedis, posterior tibial), and retroperitoneal bleeding (back/flank pain, tachycardia, hypotension). Maintain bed rest per protocol."),
  rn("NCLEX-RN","Respiratory",3,"A client with acute respiratory failure has a PaO2 of 50 mmHg and PaCO2 of 55 mmHg on room air. This represents:",["Type 1 respiratory failure only","Combined type 1 (hypoxemic) and type 2 (hypercapnic) respiratory failure","Normal blood gas values","Only metabolic acidosis"],1,"Type 1 (hypoxemic): PaO2 < 60 mmHg. Type 2 (hypercapnic): PaCO2 > 50 mmHg. This client has both: hypoxemia AND hypercapnia, indicating combined failure. Common in COPD exacerbation, severe asthma, and neuromuscular disease. Treatment: supplemental oxygen, possible BiPAP or intubation."),
  rn("NCLEX-RN","Respiratory",3,"A client with massive hemoptysis (> 100 mL in 24 hours) should be positioned:",["Supine with head elevated","With the affected (bleeding) lung dependent (down) to prevent blood from entering the unaffected lung","In Trendelenburg position","Sitting upright"],1,"Position the bleeding lung down (gravity keeps blood in the affected lung, protecting the unaffected lung from aspiration). This is the opposite of typical pneumonia positioning. Emergency management: secure airway, large-bore IV access, type and crossmatch, bronchoscopy for source identification, and possible bronchial artery embolization."),
  rn("NCLEX-RN","Respiratory",3,"A client with severe asthma exacerbation has a silent chest on auscultation. This finding indicates:",["Improvement in asthma symptoms","Critical airflow limitation requiring immediate intubation preparation","Mild bronchospasm","Normal finding during treatment"],1,"Silent chest in asthma is ominous: severe bronchospasm prevents any air movement, so no wheezing is heard. This is a pre-arrest state. Immediate management: continuous nebulized albuterol, IV magnesium sulfate, systemic corticosteroids, prepare for intubation. Paradoxically, wheezing returning indicates improvement (air is moving)."),
  rn("NCLEX-RN","Neurological",3,"A client with subarachnoid hemorrhage develops vasospasm on post-bleed day 5. The nurse should anticipate treatment with:",["Fluid restriction","Triple-H therapy (hypertension, hypervolemia, hemodilution) and nimodipine","Hypothermia protocol","Anticoagulation therapy"],1,"Cerebral vasospasm peaks days 3-14 post-SAH, causing delayed cerebral ischemia. Nimodipine (CCB) reduces poor outcomes (given to all SAH patients for 21 days). Triple-H therapy: induced hypertension (vasopressors), hypervolemia (IV fluids), and hemodilution (maintains cerebral perfusion through spastic vessels)."),
  rn("NCLEX-RN","Neurological",3,"A client with Parkinson disease who develops on-off motor fluctuations on levodopa should have the nurse understand:",["The medication is no longer effective and should be stopped","These fluctuations represent end-of-dose wearing off and may require dose adjustment, adding COMT inhibitor, or MAO-B inhibitor","The client is non-compliant with medication","No treatment modification is needed"],1,"Motor fluctuations in PD: wearing off (return of symptoms before next dose), on-off (unpredictable symptom fluctuation), and dyskinesias (involuntary movements during peak dose). Management: fractionate levodopa doses, add COMT inhibitor (entacapone), MAO-B inhibitor (rasagiline), or consider deep brain stimulation."),
  rn("NCLEX-RN","Neurological",3,"A client with Guillain-Barre syndrome should have which monitoring priority?",["Blood glucose monitoring","Respiratory function monitoring (FVC) as ascending paralysis can compromise respiratory muscles","Cardiac enzyme monitoring","Renal function monitoring"],1,"GBS: ascending symmetric weakness that can progress to respiratory failure. Monitor FVC (forced vital capacity) every 4-6 hours: intubation considered when FVC < 20 mL/kg or < 1 L, or declining > 30%. Autonomic dysfunction (labile BP, arrhythmias) is also common. Treatment: IVIG or plasmapheresis."),
  rn("NCLEX-RN","Endocrine",3,"A client with pheochromocytoma should NOT receive which intervention before tumor removal?",["Alpha-blocker therapy","Beta-blocker therapy before adequate alpha-blockade (can cause hypertensive crisis)","IV fluids for volume expansion","Preoperative phenoxybenzamine"],1,"Pheochromocytoma preoperative preparation: alpha-blockade FIRST (phenoxybenzamine 10-14 days), then beta-blockade (only after adequate alpha-blockade). Beta-blockers before alpha-blockade causes unopposed alpha stimulation leading to severe hypertensive crisis. Liberal salt and fluid intake to restore depleted volume."),
  rn("NCLEX-RN","Endocrine",3,"A client post-thyroidectomy develops tingling around the mouth and carpopedal spasm. The nurse should assess for:",["Thyroid storm","Hypocalcemia from inadvertent parathyroid removal or damage","Wound infection","Laryngeal nerve damage"],1,"Post-thyroidectomy hypocalcemia: parathyroid glands may be damaged or removed inadvertently. Signs: perioral tingling, Chvostek sign, Trousseau sign, carpopedal spasm, tetany. Monitor serum calcium every 6-12 hours post-op. Treatment: IV calcium gluconate for acute symptomatic hypocalcemia, oral calcium and vitamin D for maintenance."),
  rn("NCLEX-RN","Endocrine",3,"A client with SIADH has serum sodium of 120 mEq/L and is symptomatic. The nurse should anticipate:",["Normal saline infusion only","Hypertonic saline (3% NaCl) with careful monitoring to avoid overcorrection","Free water administration","Desmopressin administration"],1,"Symptomatic severe hyponatremia from SIADH: hypertonic saline (3% NaCl) to raise sodium by 1-2 mEq/L per hour initially, maximum 8-10 mEq/L in 24 hours (rapid correction risks osmotic demyelination syndrome). Fluid restriction is the mainstay for chronic/mild SIADH. Tolvaptan (V2 receptor antagonist) for refractory cases."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with acute pancreatitis is managed with which initial interventions?",["Immediate oral feeding to maintain nutrition","NPO, IV fluid resuscitation, pain management, and close monitoring","Emergency surgery for all cases","Oral pancreatic enzyme supplementation"],1,"Acute pancreatitis initial management: NPO (rest the pancreas), aggressive IV fluid resuscitation (250-500 mL/hr crystalloid initially), pain management (IV opioids, avoid morphine controversy is debated), NG tube if vomiting/ileus, and monitoring for organ failure. Early enteral nutrition (within 24-48 hours) is now recommended if tolerated."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with ulcerative colitis has toxic megacolon. The nurse should prepare for:",["Increased oral intake","Emergency surgery (subtotal colectomy) if medical management fails within 24-72 hours","Outpatient management","Increased corticosteroid dose only"],1,"Toxic megacolon: colonic dilation > 6 cm with systemic toxicity (fever, tachycardia, leukocytosis). Medical trial: IV corticosteroids, broad-spectrum antibiotics, bowel rest, NG decompression, and serial abdominal X-rays. Failure to improve in 24-72 hours or perforation: emergency subtotal colectomy with end ileostomy."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with acute upper GI bleeding has a Blatchford score of 0. This indicates:",["Need for emergency endoscopy","The client can be safely managed as an outpatient without urgent endoscopy","Immediate surgical intervention","ICU admission"],1,"Blatchford score 0 (admission score): no melena, no syncope, no hepatic disease, no cardiac failure, Hgb >= 13 (men)/12 (women), BUN normal, HR < 100, SBP >= 110. These patients can be safely discharged with outpatient endoscopy. Sensitivity > 99% for identifying patients NOT needing intervention."),
  rn("NCLEX-RN","Pharmacology",3,"A client on amiodarone long-term should have which monitoring performed regularly?",["Only ECG monitoring","Thyroid function tests, pulmonary function tests, liver function tests, and ophthalmologic exams","Blood glucose only","Renal function only"],1,"Amiodarone toxicity monitoring: thyroid (both hypo- and hyperthyroidism, contains 37% iodine by weight), pulmonary (pulmonary fibrosis, DLCO annually), hepatic (LFTs every 6 months), ophthalmologic (corneal microdeposits, optic neuropathy), skin (photosensitivity, blue-gray discoloration), and neurological (tremor, ataxia)."),
  rn("NCLEX-RN","Pharmacology",3,"A client prescribed a SGLT2 inhibitor for type 2 diabetes should be educated about the risk of:",["Weight gain","Euglycemic diabetic ketoacidosis (DKA occurring with normal or near-normal blood glucose)","Hypoglycemia as primary risk","Hypertension"],1,"SGLT2 inhibitor euglycemic DKA: glucose may be < 250 mg/dL, making diagnosis challenging. Symptoms: nausea, vomiting, malaise, abdominal pain, dyspnea. Risk factors: surgery, illness, dehydration, reduced carbohydrate intake, excessive alcohol. Hold SGLT2i 3-4 days before surgery. Check ketones if unwell."),
  rn("NCLEX-RN","Pharmacology",3,"A client receiving chemotherapy with cisplatin should have which premedication protocol?",["No premedication needed","Aggressive IV hydration and antiemetic therapy (5-HT3 antagonist, dexamethasone, NK1 antagonist)","Only oral antiemetics","Acetaminophen only"],1,"Cisplatin is highly emetogenic (> 90% risk) and nephrotoxic. Premedication: triple antiemetic regimen (ondansetron + dexamethasone + aprepitant/fosaprepitant). Aggressive IV hydration before and after (maintains renal perfusion). Monitor: renal function (creatinine), electrolytes (magnesium wasting), audiometry (ototoxicity), and CBC."),
  rn("NCLEX-RN","Mental Health",3,"A client with obsessive-compulsive disorder should understand that evidence-based treatment includes:",["Benzodiazepines as first-line","Exposure and response prevention (ERP) therapy combined with SSRI pharmacotherapy","Psychoanalysis alone","Antipsychotic medications as first-line"],1,"OCD treatment: ERP (gold standard psychotherapy) involves gradual exposure to obsessional triggers while preventing compulsive rituals. SSRIs at higher doses than for depression (fluvoxamine, fluoxetine, sertraline, paroxetine). Clomipramine (TCA) is also effective. Combination ERP + SSRI is most effective."),
  rn("NCLEX-RN","Mental Health",3,"A client with generalized anxiety disorder should be taught that the first-line pharmacological treatment is:",["Benzodiazepines for long-term use","SSRIs or SNRIs as they are effective and have a favorable side effect profile for long-term management","Barbiturates","Buspirone only"],1,"GAD first-line: SSRIs (escitalopram, sertraline) or SNRIs (venlafaxine, duloxetine) for long-term management. Buspirone is an alternative (non-sedating, no dependence). Benzodiazepines for short-term or acute symptom relief only (dependence risk). CBT is the first-line psychotherapy for GAD."),
  rn("NCLEX-RN","Pediatrics",3,"A child with croup presents with barking cough, stridor, and hoarseness. The nurse should anticipate:",["Immediate intubation for all children","Nebulized epinephrine for moderate-severe stridor and oral dexamethasone","IV antibiotics for bacterial infection","Throat culture and sensitivity"],1,"Croup (laryngotracheobronchitis) management: mild (barking cough without stridor at rest): oral dexamethasone single dose. Moderate-severe (stridor at rest): nebulized racemic epinephrine (temporary relief, 2-3 hours) + dexamethasone (longer-lasting). Monitor for rebound stridor. Intubation rarely needed."),
  rn("NCLEX-RN","Pediatrics",3,"A child with type 1 diabetes and an insulin pump should have the nurse teach about:",["Never removing the pump","Rotating infusion sites every 2-3 days to prevent lipodystrophy and ensure absorption","Only using the abdomen for infusion sites","Reusing infusion sets for cost savings"],1,"Insulin pump infusion site care: rotate sites every 48-72 hours (prevent lipodystrophy, infection, and poor absorption), use abdomen, buttocks, upper arms, or thighs. Monitor site for redness, swelling, or leaking. Always have backup injection supplies. Monitor blood glucose frequently (pump malfunction = rapid DKA risk)."),
  rn("NCLEX-RN","Pediatrics",3,"A premature infant on mechanical ventilation should be monitored for retinopathy of prematurity. This condition is caused by:",["Infection","Abnormal retinal vascular development related to oxygen exposure and prematurity","Genetic factors only","Birth trauma"],1,"ROP: immature retinal blood vessels respond abnormally to oxygen (both hyperoxia and hypoxia), leading to aberrant neovascularization, retinal detachment, and blindness. Risk factors: < 32 weeks gestational age, birth weight < 1500g, and prolonged supplemental oxygen. Screening: ophthalmologic exam starting at 31 weeks postmenstrual age."),
  rn("NCLEX-RN","Maternal/Newborn",3,"A client in active labor has variable decelerations on the fetal heart rate tracing. The nurse should:",["No intervention needed","Perform amnioinfusion if recurrent, change maternal position, and assess for cord compression","Prepare for immediate cesarean delivery","Administer oxytocin to speed delivery"],1,"Variable decelerations: abrupt FHR drops (onset to nadir < 30 seconds), usually caused by umbilical cord compression. Interventions: position changes (hands and knees, lateral), amnioinfusion (replace amniotic fluid if oligohydramnios), discontinue oxytocin, vaginal exam to assess for cord prolapse. Recurrent variables with slow recovery are concerning."),
  rn("NCLEX-RN","Maternal/Newborn",3,"A client with gestational diabetes should have postpartum glucose screening at:",["No follow-up needed","4-12 weeks postpartum with a 75g oral glucose tolerance test","1 year postpartum only","Only if symptoms develop"],1,"GDM postpartum: 75g OGTT at 4-12 weeks postpartum (fasting glucose and 2-hour post-load). GDM confers 7-fold increased lifetime T2DM risk. If normal, screen every 1-3 years lifelong. Lifestyle modifications (diet, exercise, weight management) reduce progression to T2DM. Breastfeeding improves maternal glucose metabolism."),
  rn("NCLEX-RN","Renal",3,"A client with nephrotic syndrome has massive proteinuria. The nurse should anticipate:",["Fluid restriction only","Edema management, ACEi/ARB to reduce proteinuria, lipid management, and monitoring for thromboembolism","No treatment until biopsy","Only diuretic therapy"],1,"Nephrotic syndrome management: edema (loop diuretics +/- thiazides, sodium restriction), proteinuria reduction (ACEi/ARB), hyperlipidemia (statins), thromboembolism prophylaxis (hypercoagulable due to antithrombin III loss in urine), and treat underlying cause based on renal biopsy results."),
  rn("NCLEX-RN","Renal",3,"A client with contrast-induced nephropathy prevention should receive:",["No preventive measures exist","IV normal saline hydration before and after contrast administration","Oral contrast agents instead","Dialysis after contrast"],1,"CIN prevention: IV 0.9% NaCl hydration (1 mL/kg/hr for 6-12 hours before and after contrast). N-acetylcysteine (controversial, limited evidence). Use lowest contrast volume possible, use iso-osmolar or low-osmolar contrast, and hold metformin 48 hours after contrast (recheck renal function before resuming). Avoid NSAIDs."),
  rn("NCLEX-RN","Infection Control",3,"A client with vancomycin-resistant enterococci should be placed on:",["Standard precautions only","Contact precautions with gown and gloves, dedicated equipment","Airborne precautions","Droplet precautions"],1,"VRE requires contact precautions: gown and gloves upon room entry, dedicated equipment (stethoscope, BP cuff), single room (or cohort with other VRE patients), and enhanced environmental cleaning. Hand hygiene with soap and water or alcohol-based sanitizer. Treatment options limited: linezolid, daptomycin, tigecycline."),
  rn("NCLEX-RN","Hematological",3,"A client with disseminated intravascular coagulation has both thrombosis and hemorrhage simultaneously. The nurse should anticipate:",["Heparin therapy only","Treatment of the underlying cause, blood product replacement (FFP, cryoprecipitate, platelets), and possible heparin","Aspirin therapy","No treatment as the condition is self-limiting"],1,"DIC management: treat the underlying cause (sepsis, obstetric complications, malignancy), replace consumed clotting factors (FFP for prolonged PT/aPTT, cryoprecipitate for fibrinogen < 100, platelets for count < 50,000 with bleeding). Heparin may be considered for thrombosis-predominant DIC. Monitor fibrinogen, D-dimer, PT, aPTT, platelets."),
  rn("NCLEX-RN","Hematological",3,"A client with sickle cell disease in vaso-occlusive crisis should receive:",["Only oral analgesics","Aggressive IV hydration, IV opioid analgesics, supplemental oxygen if hypoxic, and warm compresses","Cold compresses to reduce inflammation","Aspirin for pain",""],1,"VOC management: aggressive hydration (1.5x maintenance IV fluids), IV opioid analgesics (patient-controlled analgesia if available, avoid meperidine/Demerol), supplemental oxygen only if SpO2 < 95%, warm compresses (vasodilation), incentive spirometry (prevent ACS), and assess for transfusion need."),
  rn("NCLEX-RN","Immunological",3,"A client with Sjogren syndrome has dry eyes and dry mouth. The nurse should teach:",["No self-care measures are available","Artificial tears, good oral hygiene, frequent sips of water, and avoiding mouth-drying medications","Limiting fluid intake","Using mouthwash containing alcohol"],1,"Sjogren management: artificial tears and lubricating eye drops (preservative-free for frequent use), pilocarpine or cevimeline (cholinergic agonists to stimulate secretion), oral hygiene (increased caries risk), sugar-free gum/lozenges, avoid anticholinergics and alcohol-containing products. Screen for lymphoma (40-fold increased risk)."),
  rn("NCLEX-RN","Integumentary",3,"A client with Stevens-Johnson syndrome has mucocutaneous lesions covering 8% of body surface area. The nurse should:",["Apply topical steroids","Transfer to a burn unit for wound care, IV fluids, and supportive management","Discharge with topical antibiotics","Administer oral antihistamines only"],1,"SJS (< 10% BSA) and TEN (> 30% BSA): severe drug reactions requiring burn unit management. Treatment: stop the offending drug, wound care similar to burns, IV fluid resuscitation, pain management, ophthalmic care (prevent ocular complications), nutritional support. Cyclosporine or IVIG may be considered. Mortality: SJS 5%, TEN 30%."),
  rn("RN-CAT","Critical Care",4,"A client with refractory status epilepticus has continued seizures despite benzodiazepines and second-line agents. The nurse should prepare for:",["Observation and supportive care","Continuous EEG monitoring, intubation, and IV anesthetic infusion (propofol, midazolam, or pentobarbital)","Oral medication administration","Discharge with outpatient follow-up"],1,"Refractory SE (fails benzodiazepines + second-line): continuous IV anesthetic (propofol, midazolam, or pentobarbital) titrated to burst suppression on continuous EEG. Requires intubation and ICU. Gradually wean after 24-48 hours of seizure suppression. Underlying etiology must be identified and treated."),
  rn("RN-CAT","Critical Care",4,"A client in septic shock requires norepinephrine to maintain MAP > 65 mmHg. If norepinephrine alone is insufficient, the nurse should anticipate adding:",["More IV fluids only","Vasopressin as a second-line vasopressor","Dobutamine as the sole agent","Nitroglycerin"],1,"Surviving Sepsis Campaign: norepinephrine is first-line vasopressor, target MAP >= 65 mmHg. If inadequate: add vasopressin (up to 0.03 U/min, reduces norepinephrine requirement). If cardiac dysfunction present: add dobutamine. Epinephrine as alternative to norepinephrine. Hydrocortisone for refractory shock."),
  rn("NCLEX-RN","Cardiovascular",3,"A client with chronic venous insufficiency has a venous stasis ulcer. The nurse should apply:",["Compression bandaging (after ruling out arterial disease with ABI)","Ice packs to the ulcer","Tight tourniquet above the ulcer","Heat pads directly on the ulcer"],0,"Venous ulcers: compression therapy is the cornerstone (graduated compression stockings or multi-layer compression bandaging). MUST rule out significant arterial disease first (ABI >= 0.8). Moist wound care, leg elevation, exercise, and treat underlying venous reflux. Venous ulcers are typically on medial malleolus, shallow, irregular borders."),
  rn("NCLEX-RN","Respiratory",3,"A client with pulmonary arterial hypertension should be prescribed which disease-specific therapy?",["ACE inhibitors","Endothelin receptor antagonists (bosentan), PDE5 inhibitors (sildenafil), or prostacyclin analogues (epoprostenol)","Beta-blockers as primary therapy","Aspirin alone"],1,"PAH-specific therapies target three pathways: endothelin (bosentan, ambrisentan, macitentan), nitric oxide/PDE5 (sildenafil, tadalafil, riociguat), and prostacyclin (epoprostenol, treprostinil, iloprost, selexipag). Combination therapy is standard. Calcium channel blockers only for the rare vasoreactive patients."),
  rn("NCLEX-RN","Neurological",3,"A client with status epilepticus should receive which first-line treatment?",["Oral phenytoin","IV benzodiazepine (lorazepam 0.1 mg/kg or diazepam 0.15 mg/kg)","IM phenobarbital","Observation for 30 minutes before treatment"],1,"Status epilepticus (seizure > 5 minutes or recurrent without recovery): first-line IV lorazepam (preferred: longer antiseizure duration than diazepam) or IM midazolam. Second-line: IV fosphenytoin, valproate, or levetiracetam. Time is critical: neuronal injury occurs with prolonged seizures. Secure airway and monitor."),
  rn("NCLEX-RN","Endocrine",3,"A client with acromegaly should understand that the first-line treatment is:",["Medication therapy alone","Transsphenoidal surgery to remove the pituitary adenoma","Radiation therapy as first-line","No treatment is necessary"],1,"Acromegaly first-line: transsphenoidal pituitary surgery (curative in 80-90% of microadenomas). Medical therapy for surgical failure or poor candidates: somatostatin analogues (octreotide, lanreotide), GH receptor antagonist (pegvisomant), or dopamine agonist (cabergoline, less effective). Monitor IGF-1 levels for disease activity."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with acute cholangitis (Charcot triad: fever, jaundice, RUQ pain) should be managed with:",["Outpatient antibiotics","IV antibiotics and urgent biliary decompression (ERCP within 24-48 hours)","Observation only","Oral pain management"],1,"Acute cholangitis: biliary obstruction with infection. Charcot triad: fever/chills, jaundice, RUQ pain. Reynolds pentad adds: altered mental status and hypotension (severe/septic cholangitis). Treatment: IV antibiotics (gram-negative and anaerobic coverage) and urgent biliary drainage via ERCP (preferred), percutaneous, or surgical."),
  rn("NCLEX-RN","Pharmacology",3,"A client receiving heparin therapy should have which reversal agent available?",["Vitamin K","Protamine sulfate (1 mg neutralizes approximately 100 units of heparin)","Fresh frozen plasma only","Idarucizumab"],1,"Protamine sulfate: positively charged protein that binds negatively charged heparin, forming a stable inactive complex. Dose: 1 mg per 100 units of UFH remaining. Give slowly IV (rapid administration causes hypotension, bradycardia, anaphylactoid reactions). Partially effective against LMWH (60-80% reversal)."),
  rn("NCLEX-RN","Mental Health",3,"A client with acute opioid withdrawal should receive which medication-assisted treatment?",["No medications should be given during withdrawal","Buprenorphine/naloxone (Suboxone) or methadone to reduce withdrawal symptoms and cravings","Benzodiazepines as primary treatment","Naltrexone during acute withdrawal"],1,"Opioid withdrawal MAT: buprenorphine/naloxone (partial agonist, can be prescribed outpatient), methadone (full agonist, requires specialized program), or clonidine/lofexidine (alpha-2 agonists for symptom relief, not MAT). Naltrexone (antagonist) is for relapse prevention AFTER detoxification. Do not give naltrexone during active withdrawal."),
  rn("NCLEX-RN","Pediatrics",3,"A child with epiglottitis should NOT have the nurse:",["Prepare emergency intubation equipment","Examine the throat or use a tongue depressor (can trigger complete airway obstruction)","Keep the child in a position of comfort","Administer supplemental oxygen"],1,"Epiglottitis: do NOT examine the throat, use a tongue depressor, or cause agitation (risk of complete airway obstruction). Keep the child calm in a position of comfort (usually sitting upright, leaning forward). Emergency airway management equipment must be at bedside. IV antibiotics (ceftriaxone) after airway is secured."),
  rn("NCLEX-RN","Maternal/Newborn",3,"A client with shoulder dystocia during delivery should have the nurse implement which maneuver?",["Apply fundal pressure","McRoberts maneuver (hyperflexion of maternal thighs to widen the pelvis)","Pull on the fetal head forcefully","Administer oxytocin to increase contractions"],1,"Shoulder dystocia maneuvers (HELPERR mnemonic): call for Help, Evaluate for Episiotomy, Legs (McRoberts - hyperflex thighs against abdomen), suprapubic Pressure (not fundal pressure), Enter (internal rotation maneuvers), Remove posterior arm, Roll to hands and knees. McRoberts is first-line (resolves 40-50% of cases)."),
  rn("NCLEX-RN","Renal",3,"A client with rhabdomyolysis should receive which priority treatment to prevent acute kidney injury?",["Oral fluid restriction","Aggressive IV fluid resuscitation with normal saline (target urine output 200-300 mL/hr)","Diuretics as sole treatment","No specific treatment needed"],1,"Rhabdomyolysis AKI prevention: aggressive IV NS (200-1000 mL/hr initially) to dilute myoglobin in the renal tubules and maintain UO > 200 mL/hr. Sodium bicarbonate (alkalinize urine to prevent myoglobin precipitation, controversial). Monitor: CK (peaks 24-72 hours), electrolytes (hyperkalemia, hyperphosphatemia, hypocalcemia), and renal function."),
  rn("NCLEX-RN","Hematological",3,"A client with immune thrombocytopenic purpura has a platelet count of 8,000. The nurse should anticipate:",["Observation only","IV immunoglobulin (IVIG) for rapid platelet increase and corticosteroids","Aspirin therapy","Immediate splenectomy"],1,"ITP with platelets < 30,000 or active bleeding: first-line treatment with corticosteroids (prednisone). IVIG for rapid platelet increase (needed within 24 hours). Anti-D immunoglobulin for Rh-positive patients. Second-line: rituximab, thrombopoietin receptor agonists (romiplostim, eltrombopag), or splenectomy."),
  rn("NCLEX-RN","Cardiovascular",3,"A client with severe mitral regurgitation and symptoms should be evaluated for:",["Medical management indefinitely","Surgical mitral valve repair (preferred over replacement when feasible)","Only diuretic therapy","Watchful waiting regardless of symptoms"],1,"Severe MR with symptoms or LV dysfunction: surgical intervention. Mitral valve repair is preferred over replacement (better outcomes, avoids lifelong anticoagulation). Robotic and minimally invasive approaches are available. MitraClip (transcatheter repair) for high surgical risk patients. Medical: diuretics, vasodilators, and beta-blockers for symptom management."),
  rn("NCLEX-RN","Respiratory",3,"A client with a flail chest segment has paradoxical chest wall movement. The nurse should anticipate:",["Chest binding to stabilize the segment","Pain management, possible mechanical ventilation for respiratory failure, and monitoring for pulmonary contusion","Immediate surgical fixation for all cases","Observation without intervention"],1,"Flail chest: 2+ adjacent ribs fractured in 2+ places creating a free-floating segment. Paradoxical movement: segment moves inward on inspiration, outward on expiration. Management: pain control (epidural analgesia is optimal), aggressive pulmonary toilet, mechanical ventilation for respiratory failure. Associated pulmonary contusion (develops over 24-48 hours) is the primary cause of hypoxemia."),
  rn("NCLEX-RN","Neurological",3,"A client with bacterial meningitis should have the nurse implement:",["Standard precautions only","Droplet precautions for N. meningitidis, IV antibiotics within 1 hour, and close contacts receive chemoprophylaxis","Contact precautions","Airborne precautions"],1,"Bacterial meningitis: empiric IV antibiotics within 1 hour (ceftriaxone + vancomycin +/- ampicillin for age > 50). Dexamethasone before or with first antibiotic dose (reduces mortality in pneumococcal meningitis). N. meningitidis: droplet precautions until 24 hours of antibiotics. Close contacts: rifampin, ciprofloxacin, or ceftriaxone chemoprophylaxis."),
  rn("NCLEX-RN","Endocrine",3,"A client with hyperparathyroidism has hypercalcemia. Which mnemonic helps remember symptoms?",["MUDPILES","Stones (kidney stones), Bones (bone pain), Groans (abdominal pain), and Psychiatric overtones (confusion, depression)","FAST","RICE"],1,"Hyperparathyroidism hypercalcemia symptoms mnemonic - Stones (nephrolithiasis, nephrocalcinosis), Bones (osteoporosis, bone pain, fractures), Groans (constipation, nausea, pancreatitis, PUD), and Psychiatric overtones (confusion, depression, fatigue). Treatment: primary hyperPTH is surgical (parathyroidectomy). Acute hypercalcemia: IV NS, loop diuretics, calcitonin, bisphosphonates."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with a Sengstaken-Blakemore tube for esophageal variceal bleeding should have which safety measure?",["No special monitoring needed","Scissors at the bedside to cut and remove the tube in case of airway obstruction from balloon migration","The tube can remain indefinitely","No airway monitoring needed"],1,"Sengstaken-Blakemore/Minnesota tube: emergency temporizing measure for uncontrolled variceal bleeding. Gastric balloon inflated first (tamponade gastric varices), then esophageal balloon if needed. Scissors at bedside (cut tube and remove if balloon migrates to pharynx causing airway obstruction). Maximum 24 hours. Endoscopic treatment is definitive."),
  rn("NCLEX-RN","Pharmacology",3,"A client prescribed methotrexate for rheumatoid arthritis should also take:",["Iron supplements","Folic acid supplementation to reduce methotrexate side effects","Vitamin K daily","Calcium supplements only"],1,"Folic acid (1 mg daily or 5 mg weekly, not on methotrexate day) reduces methotrexate side effects: stomatitis, nausea, hepatotoxicity, and cytopenias. Methotrexate inhibits dihydrofolate reductase. Monitor: CBC, LFTs, renal function. Avoid alcohol, live vaccines, and NSAIDs (increase methotrexate toxicity). Teratogenic: reliable contraception required."),
  rn("NCLEX-RN","Mental Health",3,"A client with panic disorder should understand that cognitive behavioral therapy focuses on:",["Dream interpretation","Identifying and challenging catastrophic thinking patterns and gradually confronting feared situations","Childhood trauma exploration only","Medication management alone"],1,"CBT for panic disorder: cognitive restructuring (challenging catastrophic interpretations of bodily sensations), interoceptive exposure (deliberately inducing feared sensations like racing heart), and in-vivo exposure (gradually confronting avoided situations). CBT has comparable efficacy to medications with more durable effects after discontinuation."),
  rn("NCLEX-RN","Pediatrics",3,"A child with bronchiolitis caused by RSV should be managed with:",["Routine antibiotics and bronchodilators","Supportive care: suctioning, hydration, supplemental oxygen if needed, and monitoring","Inhaled corticosteroids as primary treatment","Antiviral therapy for all cases"],1,"RSV bronchiolitis management is primarily supportive: nasal suctioning (maintains airway patency), adequate hydration (oral or IV), supplemental oxygen for SpO2 < 90%, and monitoring. Bronchodilators and corticosteroids are NOT routinely recommended (no proven benefit). Palivizumab (preventive monoclonal antibody) for high-risk infants."),
  rn("NCLEX-RN","Maternal/Newborn",3,"A client with eclampsia (seizures) should receive which medication?",["Phenytoin","Magnesium sulfate (first-line for eclamptic seizures and seizure prophylaxis in severe preeclampsia)","Diazepam as sole treatment","Phenobarbital"],1,"Magnesium sulfate: first-line for eclamptic seizures (MAGPIE trial). Loading: 4-6g IV over 20 minutes. Maintenance: 1-2g/hr continuous infusion. Monitor: deep tendon reflexes (absent = toxicity), respiratory rate (< 12 = toxicity), urine output (< 25 mL/hr = accumulation risk). Antidote: calcium gluconate 1g IV."),
  rn("NCLEX-RN","Renal",3,"A client starting peritoneal dialysis should have the nurse teach about the most common complication:",["Electrolyte imbalance only","Peritonitis (cloudy effluent, abdominal pain, fever)","Hemorrhage","Pneumothorax"],1,"PD peritonitis: most common complication. Presentation: cloudy dialysate (WBC > 100/uL), abdominal pain, fever. Most common organisms: coagulase-negative staphylococci (touch contamination). Treatment: intraperitoneal antibiotics (vancomycin + aminoglycoside or cephalosporin). Prevention: meticulous aseptic technique during exchanges."),
  rn("NCLEX-RN","Cardiovascular",3,"A client with heart failure with preserved ejection fraction (HFpEF) should be managed with:",["Aggressive neurohormonal blockade identical to HFrEF","Diuretics for volume management, blood pressure control, SGLT2 inhibitors, and treatment of comorbidities","High-dose beta-blockers as primary therapy","No treatment is available"],1,"HFpEF management: diuretics for congestion, BP control (target < 130/80), SGLT2 inhibitors (empagliflozin - EMPEROR-Preserved trial showed benefit), exercise rehabilitation, weight management, and treatment of comorbidities (AF, CAD, diabetes, sleep apnea). Unlike HFrEF, ACEi/ARB/BB have not shown mortality benefit in HFpEF."),
  rn("NCLEX-RN","Respiratory",3,"A client with a tension pneumothorax has deviation of the trachea. The trachea deviates:",["Toward the affected side","Away from the affected side (pressure pushes mediastinal structures to the contralateral side)","The trachea does not deviate","Posteriorly"],1,"Tension pneumothorax: progressive air accumulation under pressure in the pleural space. Increasing pressure pushes the mediastinum (trachea, heart) away from the affected side. Late finding (hemodynamic collapse may occur before visible deviation). Do not wait for X-ray confirmation. Immediate needle decompression is life-saving."),
  rn("NCLEX-RN","Neurological",3,"A client with myasthenia gravis has a crisis. The nurse should differentiate between myasthenic crisis and cholinergic crisis because:",["They are treated identically","Myasthenic crisis requires more anticholinesterase medication while cholinergic crisis requires stopping it","Only myasthenic crisis is dangerous","Cholinergic crisis does not exist"],1,"Edrophonium (Tensilon) test differentiates: myasthenic crisis (improves with edrophonium - under-medication) vs. cholinergic crisis (worsens with edrophonium - over-medication with anticholinesterases). Myasthenic crisis: increase medication, consider IVIG or plasmapheresis. Cholinergic crisis: hold anticholinesterases, atropine, and respiratory support."),
  rn("NCLEX-RN","Endocrine",3,"A client with diabetes mellitus presenting with altered mental status and blood glucose of 680 mg/dL without ketoacidosis likely has:",["DKA","Hyperosmolar hyperglycemic state (HHS)","Hypoglycemia","Diabetic neuropathy"],1,"HHS: extreme hyperglycemia (often > 600 mg/dL), hyperosmolarity (> 320 mOsm/kg), severe dehydration, altered mental status, and NO significant ketoacidosis (pH > 7.3, HCO3 > 18). More common in type 2 DM, elderly. Treatment: aggressive IV NS hydration (first priority, may need 6-10L deficit), insulin infusion, electrolyte replacement, and identify precipitant."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with a small bowel obstruction has high-pitched hyperactive bowel sounds and colicky pain. The nurse should prepare for:",["Immediate oral intake to push through the obstruction","NG tube decompression, IV fluid resuscitation, NPO, and surgical evaluation if conservative management fails","Enema administration","Oral laxatives"],1,"SBO management: conservative trial first (NPO, NG decompression, IV fluids, electrolyte correction) for partial obstruction or adhesive SBO without peritonitis. Surgical intervention if: complete obstruction, strangulation signs (fever, tachycardia, peritoneal signs, metabolic acidosis), closed-loop obstruction, or failure to improve in 24-72 hours."),
  rn("NCLEX-RN","Pharmacology",3,"A client receiving TPN through a central line has the solution run out. The nurse should:",["Wait for the pharmacy to send a new bag","Hang D10W or D20W to prevent rebound hypoglycemia","Discontinue the central line","Infuse normal saline at the same rate"],1,"TPN contains high dextrose concentrations. Abrupt discontinuation causes rebound hypoglycemia (endogenous insulin levels remain elevated). Hang D10W at the same rate until the next TPN bag is available. Similarly, TPN should be tapered when discontinuing (reduce rate by half for 1-2 hours before stopping). Monitor blood glucose."),
  rn("NCLEX-RN","Mental Health",3,"A client with alcohol use disorder should be offered which medication for long-term relapse prevention?",["Benzodiazepines long-term","Naltrexone (opioid antagonist that reduces cravings) or acamprosate","Disulfiram as the only option","Stimulant medications"],1,"AUD relapse prevention medications: naltrexone (reduces craving and drinking, available as daily oral or monthly injection), acamprosate (modulates glutamate/GABA, reduces post-abstinence symptoms), and disulfiram (aversion therapy - causes unpleasant reaction with alcohol). Naltrexone has strongest evidence for reducing heavy drinking."),
  rn("NCLEX-RN","Pediatrics",3,"A neonate with phenylketonuria detected on newborn screening should have:",["No dietary restrictions until symptoms appear","Immediate initiation of a phenylalanine-restricted diet to prevent intellectual disability","Only formula changes at age 6 months","Regular diet with vitamin supplementation"],1,"PKU management: immediate dietary phenylalanine restriction (detected by mandatory newborn screening at 24-48 hours of life). Special medical formula replaces breast milk/standard formula. Avoid high-protein foods (meat, dairy, eggs, nuts). Sapropterin (BH4 cofactor) helps some patients metabolize phenylalanine. Lifelong diet restriction."),
  rn("NCLEX-RN","Maternal/Newborn",3,"A client with uterine atony postpartum should have the nurse perform which intervention first?",["Prepare for hysterectomy","Fundal massage (bimanual uterine massage to stimulate uterine contraction)","Administer antibiotics","Elevate the client's legs only"],1,"Postpartum hemorrhage from uterine atony: fundal massage is the FIRST intervention. Simultaneously: empty the bladder (full bladder displaces the uterus), establish large-bore IV access, administer uterotonics (oxytocin first-line, then methylergonovine, carboprost, or misoprostol), and type and crossmatch. If refractory: intrauterine balloon tamponade, surgical intervention."),
  rn("NCLEX-RN","Renal",3,"A client with acute interstitial nephritis from medication reaction has:",["Dark brown urine with casts","Eosinophilia, rash, fever, and sterile pyuria (classic triad, but full triad in only 10%)","Only hematuria","No laboratory abnormalities"],1,"AIN: drug hypersensitivity reaction (NSAIDs, antibiotics - penicillins, cephalosporins, sulfonamides, PPIs). Classic triad (10%): fever, rash, eosinophilia. Also: eosinophiluria, sterile pyuria, mild proteinuria. Treatment: discontinue the offending drug, corticosteroids if no improvement. Most recover with drug withdrawal."),
  rn("NCLEX-RN","Cardiovascular",3,"A client with Wolff-Parkinson-White syndrome on ECG has a delta wave. If atrial fibrillation develops, the nurse should NOT administer:",["Procainamide","AV nodal blocking agents (adenosine, beta-blockers, CCBs, digoxin) as they can cause fatal ventricular fibrillation","IV amiodarone","Electrical cardioversion"],1,"WPW with atrial fibrillation: blocking the AV node forces all conduction through the accessory pathway, which can conduct rapidly to the ventricles causing VF. AVOID: adenosine, beta-blockers, CCBs, digoxin. SAFE: procainamide (slows accessory pathway), ibutilide, or electrical cardioversion. Definitive treatment: catheter ablation."),
  rn("NCLEX-RN","Respiratory",3,"A client with acute exacerbation of COPD should receive which initial therapy?",["Long-acting bronchodilators only","Short-acting bronchodilators (albuterol + ipratropium), systemic corticosteroids, and antibiotics if indicated","IV aminophylline as first-line","High-flow oxygen at 15 L/min"],1,"AECOPD management: short-acting bronchodilators (nebulized albuterol + ipratropium), systemic corticosteroids (prednisone 40mg x 5 days per REDUCE trial), antibiotics if increased dyspnea + increased sputum volume + increased sputum purulence, controlled oxygen (SpO2 88-92%), and non-invasive ventilation (BiPAP) for respiratory acidosis."),
  rn("NCLEX-RN","Neurological",3,"A client with a cerebellar stroke presents with:",["Contralateral hemiplegia","Ataxia, vertigo, nystagmus, and dysarthria without hemiplegia","Aphasia and facial droop","Bilateral lower extremity weakness"],1,"Cerebellar stroke presentation: ataxia (truncal and appendicular), vertigo, nystagmus, dysarthria, and ipsilateral incoordination without hemiplegia. Can be life-threatening due to posterior fossa edema compressing the brainstem. Emergency: suboccipital decompressive craniectomy for cerebellar edema with brainstem compression."),
  rn("NCLEX-RN","Endocrine",3,"A client with Addisonian crisis presents with hypotension, hyperkalemia, and hyponatremia. Emergency treatment includes:",["Fluid restriction","IV hydrocortisone 100mg bolus, IV normal saline, and dextrose for hypoglycemia","Insulin administration","Potassium supplementation"],1,"Addisonian crisis: life-threatening adrenal insufficiency. Treatment: IV hydrocortisone 100mg bolus then 50-100mg every 6-8 hours (provides both glucocorticoid and mineralocorticoid activity at stress doses), aggressive IV NS (correct hypovolemia and hyponatremia), D5 if hypoglycemic, and identify/treat the precipitant (infection, surgery, stress)."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with spontaneous bacterial peritonitis has ascitic fluid with a PMN count greater than 250 cells/mm3. Treatment includes:",["Oral antibiotics only","IV ceftriaxone (or cefotaxime) and IV albumin to prevent hepatorenal syndrome","Diagnostic paracentesis only","Surgical washout"],1,"SBP treatment: empiric IV third-generation cephalosporin (cefotaxime or ceftriaxone). IV albumin (1.5 g/kg at diagnosis, 1 g/kg on day 3) reduces renal failure and mortality. Secondary prophylaxis: norfloxacin or TMP-SMX daily (lifelong or until liver transplant). SBP is diagnosed by ascitic fluid PMN > 250."),
  rn("NCLEX-RN","Pharmacology",3,"A client receiving IV potassium chloride should have the infusion rate limited to:",["40 mEq/hr through a peripheral line","10 mEq/hr through a peripheral IV line (20 mEq/hr through central line with cardiac monitoring)","No rate restriction","100 mEq/hr if severely hypokalemic"],1,"IV KCl safety: peripheral IV max 10 mEq/hr at max concentration 40 mEq/L (to prevent phlebitis and cardiac arrhythmias). Central line: max 20 mEq/hr at higher concentration, with continuous cardiac monitoring. NEVER give IV push (fatal arrhythmia). Infusion pump required. Max 200 mEq/24 hours."),
  rn("NCLEX-RN","Pharmacology",3,"A client on warfarin who needs emergency surgery should receive:",["Oral vitamin K only","IV vitamin K and 4-factor prothrombin complex concentrate (PCC) for rapid INR reversal","Fresh frozen plasma only","No reversal needed for surgery"],1,"Emergency warfarin reversal: IV vitamin K 10mg (takes 6-24 hours for full effect) PLUS 4-factor PCC (contains factors II, VII, IX, X - provides immediate reversal within 30 minutes). PCC is preferred over FFP: smaller volume, faster administration, more predictable INR correction, and no need for ABO matching."),
  rn("NCLEX-RN","Mental Health",3,"A client with bulimia nervosa has which characteristic laboratory finding?",["Hyperkalemia","Metabolic alkalosis and hypokalemia from purging","Metabolic acidosis","Hypercalcemia"],1,"Bulimia purging: vomiting causes loss of HCl (metabolic alkalosis) and potassium (hypokalemia). Hypokalemia can cause fatal cardiac arrhythmias. Also: parotid gland enlargement (chipmunk cheeks), dental enamel erosion, Russell's sign (calluses on knuckles from self-induced vomiting), and esophageal tears (Mallory-Weiss)."),
  rn("NCLEX-RN","Pediatrics",3,"A child with meningococcemia has a petechial rash that rapidly progresses to purpura. The nurse should anticipate:",["Observation of the rash","Immediate IV antibiotics, aggressive fluid resuscitation, and monitoring for DIC and adrenal hemorrhage (Waterhouse-Friderichsen syndrome)","Topical antibiotics to the rash","Antihistamine administration"],1,"Meningococcemia: rapidly progressive petechial/purpuric rash with septic shock. Waterhouse-Friderichsen syndrome: bilateral adrenal hemorrhage causing acute adrenal insufficiency. Treatment: immediate IV antibiotics (ceftriaxone), aggressive IV fluids, vasopressors, stress-dose steroids, and DIC management. High mortality without rapid treatment."),
  rn("NCLEX-RN","Maternal/Newborn",3,"A client with cord prolapse should be managed by:",["Pushing the cord back into the uterus","Elevating the presenting part off the cord (examiner's hand in vagina) and positioning in Trendelenburg/knee-chest while preparing for emergency cesarean delivery","Continuing labor with close monitoring","Applying traction to the cord"],1,"Cord prolapse: obstetric emergency. Immediately: examiner's gloved hand in vagina elevating the presenting part off the cord (continuous pressure until delivery), position client in knee-chest or steep Trendelenburg, fill bladder with 500-700 mL NS (elevates presenting part), avoid handling the cord, and prepare for emergency cesarean delivery."),
  rn("NCLEX-RN","Renal",3,"A client with polycystic kidney disease should avoid which medication class?",["ACE inhibitors","NSAIDs (can accelerate renal decline and cause hypertension in PKD)","Statins","Calcium supplements"],1,"NSAIDs in PKD: reduce renal blood flow (prostaglandin inhibition), worsen hypertension, accelerate renal decline, and may cause AKI. Also avoid nephrotoxic agents. ACEi/ARBs are actually the preferred antihypertensives in PKD. Tolvaptan slows cyst growth in rapidly progressive ADPKD."),
  rn("NCLEX-RN","Infection Control",3,"A client with Clostridioides difficile infection should have the room cleaned with:",["Standard hospital-grade disinfectant","Bleach-based (hypochlorite) solution as C. diff spores are resistant to alcohol and quaternary ammonium compounds","Alcohol-based disinfectant","Soap and water only"],1,"C. diff spores survive on surfaces for months and are resistant to alcohol-based sanitizers and most standard disinfectants. Bleach (sodium hypochlorite) or EPA-registered sporicidal disinfectant is required. Hand hygiene: soap and water (not alcohol-based sanitizer). Contact precautions, single room, and dedicated equipment."),
  rn("NCLEX-RN","Hematological",3,"A client with von Willebrand disease type 1 should receive which treatment before minor surgery?",["Factor VIII concentrate only","Desmopressin (DDAVP) which stimulates release of vWF and factor VIII from endothelial stores","Platelet transfusion","No pretreatment needed"],1,"Type 1 vWD (most common, 80%): partial quantitative deficiency. DDAVP releases stored vWF and factor VIII from endothelial Weibel-Palade bodies. Given IV or intranasally 30-60 minutes before procedure. Effective for type 1, some type 2. NOT effective for type 3 (severe, no vWF stores). Alternative: Humate-P (vWF/factor VIII concentrate)."),
  rn("NCLEX-RN","Immunological",3,"A client with new-onset type 1 diabetes is screened for associated autoimmune conditions. The nurse should anticipate screening for:",["Rheumatoid arthritis only","Celiac disease and thyroid disease (both frequently associated with T1DM)","Lupus","Multiple sclerosis"],1,"T1DM autoimmune associations: celiac disease (screen with tissue transglutaminase IgA at diagnosis and periodically), autoimmune thyroid disease (screen TSH at diagnosis and annually), Addison disease, and pernicious anemia. Screening allows early detection and treatment of associated conditions."),
  rn("NCLEX-RN","Cardiovascular",3,"A client with stable angina undergoes exercise stress testing. A positive test is indicated by:",["Normal blood pressure response","ST-segment depression of 1 mm or more during exercise","Increased heart rate only","Normal ECG throughout testing"],1,"Positive exercise stress test: ST depression >= 1 mm (horizontal or downsloping) during or after exercise suggests myocardial ischemia. Other positive findings: exercise-induced angina, hypotension, ventricular arrhythmias, or failure to increase BP appropriately. Sensitivity ~70%, specificity ~75%. Follow up with coronary angiography or imaging stress test."),
  rn("NCLEX-RN","Respiratory",3,"A client receiving non-invasive positive pressure ventilation (BiPAP) for acute COPD exacerbation should be monitored for:",["Only respiratory improvement","Mask discomfort, skin breakdown, aspiration risk, and gastric distension","No monitoring is needed","Only oxygen saturation"],1,"BiPAP monitoring: respiratory status (rate, pattern, SpO2, ABG), mask fit (air leaks reduce effectiveness), facial skin integrity (pressure injury under mask), aspiration risk (elevated gastric pressure, keep NPO or light diet), gastric distension, and patient tolerance/anxiety. Contraindications: altered consciousness, facial trauma, copious secretions."),
  rn("NCLEX-RN","Neurological",3,"A client with transverse myelitis has acute bilateral leg weakness and sensory level at T10. The nurse should anticipate:",["Outpatient physical therapy only","MRI of the spine, IV corticosteroids, and monitoring for respiratory compromise if the level ascends","CT scan only","No imaging needed"],1,"Transverse myelitis: inflammatory demyelination of the spinal cord. MRI shows cord enhancement. Treatment: high-dose IV methylprednisolone (reduces inflammation and disability). Plasmapheresis for steroid-refractory cases. Monitor for ascending myelitis (can compromise respiratory function). Rule out compressive myelopathy (neurosurgical emergency)."),
  rn("NCLEX-RN","Endocrine",3,"A client with primary aldosteronism (Conn syndrome) has hypertension and hypokalemia. The nurse should anticipate screening with:",["Thyroid function tests","Aldosterone-to-renin ratio (ARR) as the initial screening test","Random cortisol levels","ACTH stimulation test"],1,"Primary aldosteronism screening: ARR (aldosterone-to-renin ratio). High aldosterone with low/suppressed renin confirms autonomous aldosterone production. Follow with confirmatory testing (salt loading test, fludrocortisone suppression test). CT adrenal to identify adenoma vs. bilateral hyperplasia. Treatment: adrenalectomy for adenoma, spironolactone for hyperplasia."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with Zollinger-Ellison syndrome has recurrent peptic ulcers and diarrhea. The nurse should understand this is caused by:",["H. pylori infection","Gastrinoma (gastrin-secreting tumor) causing excessive acid secretion","Stress-related ulcers","Medication-induced ulcers"],1,"ZES: gastrinoma (usually in duodenum or pancreas) secretes excess gastrin causing massive acid hypersecretion. Results: recurrent/refractory peptic ulcers (especially unusual locations), diarrhea (acid inactivates pancreatic enzymes), and GERD. Diagnosis: fasting gastrin > 10x ULN, secretin stimulation test. Treatment: PPI, surgical resection of tumor. Screen for MEN1."),
  rn("NCLEX-RN","Pharmacology",3,"A client prescribed lithium should maintain adequate hydration and sodium intake because:",["Lithium has no interaction with sodium","Sodium depletion causes increased lithium reabsorption in the kidneys, leading to toxicity","Lithium causes dehydration directly","Sodium increases lithium excretion excessively"],1,"Lithium is reabsorbed in the proximal tubule alongside sodium. When sodium is depleted (dehydration, sodium restriction, diuretics), the kidney compensates by reabsorbing more sodium AND lithium, raising lithium levels to toxic range. Maintain consistent sodium and fluid intake. Risk: diuretics, NSAIDs, ACEi (all reduce lithium excretion)."),
  rn("NCLEX-RN","Mental Health",3,"A client with ADHD in adulthood should be offered which first-line medication?",["Benzodiazepines","Stimulant medications (methylphenidate or amphetamine-based) as first-line treatment","Antipsychotics","SSRIs as first-line"],1,"Adult ADHD first-line: stimulant medications (methylphenidate or mixed amphetamine salts). Extended-release formulations preferred for adherence and consistent symptom control. Non-stimulant alternatives: atomoxetine, bupropion, guanfacine. Monitor: cardiovascular effects (HR, BP), appetite/weight, sleep, and potential for misuse."),
  rn("NCLEX-RN","Pediatrics",3,"A child with suspected appendicitis should NOT receive:",["IV fluids","Pain medication before surgical evaluation (providing analgesia does not mask appendicitis and should not be withheld)","Laxatives or enemas (can cause appendiceal perforation)","IV antibiotics"],2,"Laxatives and enemas are contraindicated in suspected appendicitis: can increase intraluminal pressure and precipitate appendiceal perforation. Pain management should NOT be withheld (old practice of withholding analgesia to preserve physical exam findings is no longer supported - studies show analgesia does not reduce diagnostic accuracy)."),
  rn("NCLEX-RN","Maternal/Newborn",3,"A laboring client with late decelerations on fetal monitoring has:",["Normal fetal heart rate pattern","Uteroplacental insufficiency causing gradual FHR decrease that begins after the contraction peak and recovers after the contraction ends","Cord compression","Head compression"],1,"Late decelerations: gradual FHR decrease with onset at or after the contraction peak, nadir after the peak, and return to baseline after the contraction ends. Caused by uteroplacental insufficiency (maternal hypotension, placental abruption, uterine hyperstimulation). Recurrent late decelerations are concerning and may require emergent delivery."),
  rn("NCLEX-RN","Renal",3,"A client with uremic pericarditis from ESRD should be treated with:",["NSAIDs as primary treatment","Intensified dialysis (daily hemodialysis until symptoms resolve)","Antibiotics","Colchicine as sole therapy"],1,"Uremic pericarditis: occurs in inadequately dialyzed ESRD patients (BUN usually > 60 mg/dL). Treatment: intensified/daily dialysis (most effective). NSAIDs may be used adjunctively but are less effective than dialysis intensification. Heparin-free dialysis preferred (risk of hemorrhagic pericardial effusion). Monitor for cardiac tamponade."),
  rn("NCLEX-RN","Cardiovascular",3,"A client with Brugada syndrome on ECG has coved ST elevation in leads V1-V3. The nurse should understand this condition:",["Is benign and requires no treatment","Carries a risk of sudden cardiac death from ventricular fibrillation; an ICD may be indicated","Only occurs in elderly patients","Is treated with beta-blockers"],1,"Brugada syndrome: inherited channelopathy with characteristic coved-type ST elevation in V1-V3 and risk of polymorphic VT/VF and sudden cardiac death. ICD is indicated for survivors of cardiac arrest or those with syncope. Avoid: fever (unmasks or worsens ECG pattern - treat aggressively), certain drugs (sodium channel blockers, TCAs)."),
  rn("NCLEX-RN","Respiratory",3,"A client with obstructive sleep apnea and an AHI of 22 should be prescribed:",["Oral decongestants","Continuous positive airway pressure (CPAP) as first-line treatment for moderate-severe OSA","Surgery as first-line","Only positional therapy"],1,"CPAP is first-line for moderate-severe OSA (AHI >= 15 or >= 5 with symptoms). CPAP splints the upper airway open, preventing collapse during sleep. Benefits: reduces daytime somnolence, improves cardiovascular outcomes, and reduces accident risk. Alternatives: oral appliances (mild-moderate), surgery (selected cases), or hypoglossal nerve stimulator."),
  rn("NCLEX-RN","Neurological",3,"A client with autonomic dysreflexia from a spinal cord injury at T4 has a sudden blood pressure of 220/120 and pounding headache. The nurse should first:",["Administer antihypertensive medication","Sit the client upright and identify and remove the triggering stimulus (usually bladder distension or bowel impaction)","Lower the head of bed","Administer IV fluids"],1,"Autonomic dysreflexia (SCI at T6 or above): life-threatening hypertensive emergency triggered by noxious stimulus below the injury level. FIRST: sit upright (orthostatic reduction in BP), then identify and remove the trigger. Check: foley catheter (kinked, blocked?), bladder distension (straight catheterize), fecal impaction, tight clothing, skin issues. Antihypertensives if BP does not improve."),
  rn("NCLEX-RN","Endocrine",3,"A client with Graves disease develops exophthalmos. The nurse should teach:",["No eye care is needed","Protect the eyes with lubricating drops, elevate HOB during sleep, and use sunglasses to prevent corneal drying and injury","Exophthalmos resolves immediately with treatment","Eye patches should be worn at all times"],1,"Graves ophthalmopathy: autoimmune inflammation of orbital tissues causing proptosis, lid lag, and exposure keratopathy. Eye care: artificial tears frequently, lubricating ointment at night, elevate HOB (reduces orbital edema), sunglasses (UV and wind protection), and tape eyelids closed during sleep if cannot fully close. Severe cases: IV steroids, orbital radiation, or decompression surgery."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with cirrhosis and ascites should have a therapeutic paracentesis. The nurse should anticipate administering:",["Nothing additional","IV albumin (6-8 g per liter of fluid removed over 5L) to prevent post-paracentesis circulatory dysfunction","Hypertonic saline","Packed red blood cells"],1,"Large-volume paracentesis (> 5L): albumin replacement (6-8g per liter removed) prevents post-paracentesis circulatory dysfunction (PPCD): systemic vasodilation, renal impairment, hyponatremia, and increased mortality. For < 5L, albumin replacement is less critical but still recommended. Monitor: vitals, electrolytes, and abdominal girth."),
  rn("NCLEX-RN","Pharmacology",3,"A client on a monoamine oxidase inhibitor should be taught to avoid tyramine-containing foods because:",["They cause nausea","Tyramine interaction can cause hypertensive crisis (severe headache, hypertension, stroke risk)","They reduce drug absorption","They cause hypoglycemia"],1,"MAOI + tyramine interaction: tyramine is normally metabolized by MAO in the gut. MAOIs block this metabolism, allowing tyramine to enter circulation and cause massive norepinephrine release (hypertensive crisis: severe headache, neck stiffness, palpitations, diaphoresis, stroke risk). Avoid: aged cheeses, cured meats, red wine, fermented foods, and soy sauce."),
  rn("NCLEX-RN","Mental Health",3,"A client with conversion disorder (functional neurological symptom disorder) has paralysis with no organic cause. The nurse should:",["Confront the client about faking symptoms","Acknowledge the symptoms as real to the client and focus on rehabilitation and stress management","Ignore the symptoms completely","Order more diagnostic tests repeatedly"],1,"Conversion disorder: neurological symptoms without organic disease (but NOT malingering - symptoms are involuntary and real to the patient). Management: validate the patient's experience (not faking), physical therapy/rehabilitation, psychotherapy (CBT), stress management, and education. Avoid excessive testing (reinforces illness behavior)."),
  rn("NCLEX-RN","Pediatrics",3,"A neonate with hyperbilirubinemia requiring phototherapy should have the nurse:",["Cover the entire body during phototherapy","Expose maximum skin surface area, protect the eyes with opaque eye shields, and monitor temperature","Apply sunscreen to the skin","Dress the infant in a onesie during treatment"],1,"Phototherapy nursing care: maximize skin exposure (diaper only), opaque eye shields (prevent retinal damage), monitor temperature (hyperthermia or hypothermia risk), increase fluid intake (insensible fluid losses from skin), monitor bilirubin levels, assess skin for bronze discoloration, and note stool output (photoisomers are excreted in stool)."),
  rn("NCLEX-RN","Maternal/Newborn",3,"A client with a previous cesarean delivery who desires vaginal birth after cesarean (VBAC) should be counseled about:",["No risks associated with VBAC","The risk of uterine rupture (approximately 0.5-0.7% with a low transverse incision) and the need for continuous monitoring","VBAC is always contraindicated","Only elective repeat cesarean is safe"],1,"TOLAC/VBAC: success rate 60-80%. Uterine rupture risk: 0.5-0.7% (low transverse scar). Requirements: continuous fetal monitoring, ability to perform emergency cesarean within 30 minutes, informed consent. Contraindications: classical (vertical) uterine scar, prior uterine rupture, and placenta previa covering the scar."),
  rn("NCLEX-RN","Renal",3,"A client with minimal change disease (most common nephrotic syndrome in children) should expect treatment with:",["Antibiotics","Corticosteroids (> 90% respond to steroid therapy within 8 weeks)","Immediate dialysis","Surgical intervention"],1,"Minimal change disease: most common cause of nephrotic syndrome in children (80%). Excellent prognosis: > 90% respond to corticosteroids (prednisone) within 8 weeks. Relapses are common (40-50% relapse). Frequently relapsing disease: add steroid-sparing agents (cyclophosphamide, cyclosporine, mycophenolate). Renal biopsy shows normal light microscopy, foot process effacement on electron microscopy."),
  rn("NCLEX-RN","Cardiovascular",3,"A client with symptomatic severe aortic regurgitation should have the nurse anticipate:",["Medical management indefinitely","Aortic valve replacement (surgical or TAVR) before irreversible LV dysfunction develops","No follow-up needed","Only exercise restriction"],1,"Severe AR with symptoms or LV dysfunction (LVEF < 50% or LV dilation): aortic valve replacement. Surgery before irreversible LV damage improves outcomes. Medical management for asymptomatic patients or surgical contraindications: vasodilators (ACEi/ARB, nifedipine), serial echocardiographic monitoring of LV size and function."),
  rn("NCLEX-RN","Respiratory",3,"A client on a mechanical ventilator develops ventilator-associated pneumonia. Prevention strategies include:",["Keeping the HOB flat","Elevating HOB 30-45 degrees, oral care with chlorhexidine, daily sedation vacation, and daily assessment of readiness to extubate","Routine prophylactic antibiotics","Avoiding oral care"],1,"VAP prevention bundle: HOB elevation 30-45 degrees, daily sedation interruption and spontaneous breathing trial, DVT and stress ulcer prophylaxis, oral care with chlorhexidine (0.12%), subglottic suctioning, and daily assessment of extubation readiness. VAP significantly increases morbidity, mortality, ICU stay, and cost."),
  rn("NCLEX-RN","Neurological",3,"A client with a subdural hematoma has a crescent-shaped hyperdensity on CT. The nurse should understand:",["This is always a surgical emergency","Acute subdural hematoma with midline shift or neurological decline requires emergent surgical evacuation","All subdural hematomas resolve spontaneously","No monitoring is needed"],1,"Subdural hematoma: crescent-shaped bleeding between the dura and arachnoid. Acute SDH (< 3 days): hyperdense on CT, often from bridging vein tears (trauma, anticoagulants, elderly). Surgical evacuation indicated for: thickness > 10mm, midline shift > 5mm, or neurological deterioration. Small asymptomatic SDH may be monitored."),
  rn("NCLEX-RN","Endocrine",3,"A client with type 1 diabetes using an insulin pump who develops DKA should have the nurse:",["Continue the pump at the same rate","Remove the pump infusion set, administer insulin via injection or IV, and troubleshoot the pump","Increase the pump rate and wait","Stop all insulin"],1,"Pump failure is a common DKA precipitant in T1DM (only rapid-acting insulin, no long-acting depot). DKA develops within hours of pump failure. Management: remove the pump site (may be kinked, displaced, or infected), administer insulin via SQ injection or IV infusion, treat DKA per protocol. Troubleshoot pump before resuming."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with Budd-Chiari syndrome has hepatic vein thrombosis causing hepatomegaly and ascites. The nurse should anticipate:",["No treatment needed","Anticoagulation and possible TIPS or surgical decompression","Only diuretics","Liver biopsy without other intervention"],1,"Budd-Chiari: hepatic vein obstruction causing hepatic congestion, hepatomegaly, ascites, and eventually liver failure. Treatment: anticoagulation (treat the thrombosis), diuretics for ascites, TIPS (transjugular intrahepatic portosystemic shunt) for decompression, and liver transplant for severe/fulminant disease. Screen for underlying thrombophilia or myeloproliferative disorder."),
  rn("NCLEX-RN","Pharmacology",3,"A client receiving continuous IV insulin infusion should have blood glucose monitored:",["Every 8 hours","Every 1-2 hours to prevent hypoglycemia and guide dose adjustments","Once daily","Only when symptoms develop"],1,"Continuous insulin infusion: monitor blood glucose every 1-2 hours (some protocols every 30-60 minutes during titration). Insulin drip has a very short half-life (5-10 minutes); glucose can change rapidly. Transition to SC insulin 1-2 hours before stopping the drip (overlap needed to prevent rebound hyperglycemia). Monitor potassium concurrently."),
  rn("NCLEX-RN","Mental Health",3,"A client presenting with catatonia should have the nurse anticipate treatment with:",["Antipsychotics as first-line","Benzodiazepines (lorazepam challenge) as first-line for catatonia, followed by ECT if unresponsive","SSRIs","Physical therapy"],1,"Catatonia treatment: lorazepam challenge (1-2mg IV/IM; dramatic improvement supports diagnosis and treatment). Continue benzodiazepines if responsive. ECT is highly effective for benzodiazepine-refractory catatonia (90% response rate). Avoid antipsychotics in catatonia (can worsen symptoms or precipitate neuroleptic malignant syndrome). Supportive care: DVT prevention, nutrition, hydration."),
  rn("NCLEX-RN","Pediatrics",3,"A child with hemolytic uremic syndrome presents with the triad of:",["Fever, rash, and joint pain","Microangiopathic hemolytic anemia, thrombocytopenia, and acute renal failure","Cough, wheezing, and fever","Vomiting, diarrhea, and constipation"],1,"HUS triad: microangiopathic hemolytic anemia (schistocytes on smear, elevated LDH, low haptoglobin), thrombocytopenia, and acute kidney injury. Usually follows E. coli O157:H7 (Shiga toxin) diarrheal illness. Treatment: supportive (IV fluids, transfusions, dialysis if needed). Antibiotics do NOT help and may worsen STEC-HUS."),
  rn("NCLEX-RN","Maternal/Newborn",3,"A client in the third trimester with sudden onset severe abdominal pain, rigid boardlike abdomen, and vaginal bleeding should be evaluated for:",["Normal Braxton Hicks contractions","Placental abruption (premature separation of the placenta from the uterine wall)","Placenta previa","Round ligament pain"],1,"Placental abruption: painful vaginal bleeding (80% external bleeding, 20% concealed), rigid/tender uterus (boardlike), fetal distress, and possible DIC. Risk factors: hypertension, trauma, cocaine use, prior abruption, and PPROM. Emergency: stabilize mother (IV fluids, blood products), continuous fetal monitoring, and emergent delivery if severe."),
  rn("NCLEX-RN","Renal",3,"A client with membranous nephropathy and nephrotic-range proteinuria should be educated that:",["No treatment is needed","One-third of cases spontaneously remit, so observation may be appropriate for some patients before initiating immunosuppressive therapy","All cases require immediate immunosuppression","Dialysis is always needed"],1,"Membranous nephropathy: rule of thirds - 1/3 spontaneous remission, 1/3 stable proteinuria, 1/3 progressive to ESRD. Observe for 6-12 months if low risk. High-risk (declining GFR, massive proteinuria): immunosuppressive therapy (rituximab, cyclophosphamide/steroids, or calcineurin inhibitors). ACEi/ARB for all. Screen for underlying causes (malignancy, SLE, hepatitis B)."),
  rn("NCLEX-RN","Infection Control",3,"A healthcare worker exposed to hepatitis B from a needlestick should receive:",["No post-exposure prophylaxis","Hepatitis B immune globulin (HBIG) and hepatitis B vaccine series if not previously vaccinated or non-responder","Only hepatitis B vaccine","Antibiotics"],1,"HBV needlestick PEP depends on vaccination status: unvaccinated: HBIG + start HBV vaccine series. Previously vaccinated with known adequate response (anti-HBs >= 10): no treatment. Non-responder: HBIG x2 or HBIG + revaccination. Test source patient for HBsAg. PEP should be given within 24 hours of exposure."),
  rn("NCLEX-RN","Hematological",3,"A client with polycythemia vera has an elevated hematocrit. The goal of treatment is to maintain hematocrit below:",["50%","45% to reduce thrombotic risk","55%","60%"],1,"PV treatment target: hematocrit < 45% (CYTO-PV trial showed reduced cardiovascular events and death). First-line: therapeutic phlebotomy (remove 450-500 mL blood until target reached). Low-dose aspirin (81mg daily). Cytoreductive therapy (hydroxyurea) for high-risk patients (age > 60, prior thrombosis). Monitor for transformation to myelofibrosis or AML."),

  // === NP (80 questions) ===
  np("AANP","Cardiovascular",3,"A patient with newly diagnosed atrial fibrillation should have stroke risk assessed using:",["CHADS-VASc score only without further action","CHA2DS2-VASc score to determine if anticoagulation is indicated","TIMI score","Wells criteria"],1,"CHA2DS2-VASc: CHF (1), HTN (1), Age >= 75 (2), DM (1), Stroke/TIA/VTE (2), Vascular disease (1), Age 65-74 (1), Sex-female (1). Score >= 2 in men, >= 3 in women: anticoagulation recommended. Score 1 in men, 2 in women: consider anticoagulation. Score 0: no anticoagulation needed."),
  np("AANP","Cardiovascular",3,"A patient with stable CAD and prior stent placement should receive dual antiplatelet therapy with aspirin and clopidogrel for:",["1 month for all stents","12 months for drug-eluting stents (may be shortened to 6 months if high bleeding risk)","Lifelong dual therapy","1 week only"],1,"DAPT duration after PCI: drug-eluting stent: minimum 6 months (12 months standard), bare-metal stent: minimum 1 month. Extended DAPT (> 12 months) for high ischemic/low bleeding risk. Shortened DAPT (3-6 months) for high bleeding risk. Aspirin continues indefinitely. P2Y12 inhibitor options: clopidogrel, ticagrelor, prasugrel."),
  np("AANP","Respiratory",3,"A patient with newly diagnosed asthma should be classified by severity to guide initial treatment. Moderate persistent asthma is defined as:",["Symptoms less than 2 days per week","Symptoms daily with nighttime awakenings greater than once per week and FEV1 60-80% predicted","Symptoms only during exercise","Severe symptoms requiring daily oral steroids"],1,"Asthma severity classification: intermittent (symptoms <= 2 days/week, <= 2 nights/month, FEV1 > 80%), mild persistent (> 2 days/week, 3-4 nights/month, FEV1 > 80%), moderate persistent (daily symptoms, > 1 night/week, FEV1 60-80%), severe persistent (throughout the day, nightly, FEV1 < 60%). Step therapy based on classification."),
  np("NP-CAT","Respiratory",4,"A patient with chronic hypercapnic respiratory failure from COPD should be evaluated for:",["Only supplemental oxygen","Home non-invasive ventilation (BiPAP) in addition to LTOT","Tracheostomy for all patients","No long-term treatment"],1,"Chronic hypercapnic COPD (PaCO2 >= 52 with history of hospitalization for acute exacerbation): home NIV (BiPAP) reduces readmissions and mortality (HOT-HMV trial). Settings: backup rate, adequate IPAP to normalize PaCO2, adequate EPAP for auto-PEEP. Combine with LTOT. Improves quality of life and exercise tolerance."),
  np("AANP","Neurological",3,"A patient presenting with new-onset headache described as thunderclap should have which immediate evaluation?",["Prescribe migraine medication","CT head without contrast followed by lumbar puncture if CT is negative to rule out subarachnoid hemorrhage","Reassurance and follow-up in 1 week","MRI in 2 weeks"],1,"Thunderclap headache: maximal intensity at onset (peak within seconds to minutes). Must rule out SAH (mortality 50% if untreated). Non-contrast CT: 98% sensitive within 6 hours (decreases over days). If CT negative: LP for xanthochromia (breakdown of RBCs in CSF). CTA to identify aneurysm. Other causes: RCVS, CVT, arterial dissection."),
  np("AANP","Endocrine",3,"A patient with osteoporosis and T-score of -3.0 who has a contraindication to bisphosphonates should be considered for:",["Calcium supplementation alone","Denosumab, teriparatide, or romosozumab as alternative osteoporosis therapies","No treatment","Exercise alone"],1,"Non-bisphosphonate osteoporosis treatments: denosumab (RANKL inhibitor, SC every 6 months), teriparatide/abaloparatide (PTH analogue, anabolic - builds new bone), romosozumab (sclerostin inhibitor, anabolic + anti-resorptive). Important: discontinuing denosumab causes rapid bone loss (must transition to bisphosphonate). Teriparatide limited to 2 years."),
  np("AANP","Gastrointestinal",3,"A patient with elevated liver enzymes and suspected NAFLD should have fibrosis assessed using:",["Only liver biopsy","FIB-4 index or NAFLD fibrosis score as non-invasive screening, followed by elastography if intermediate risk","Ultrasound alone","CT scan of the abdomen"],1,"NAFLD fibrosis assessment: start with non-invasive scores (FIB-4, NFS). Low risk: monitor. Intermediate: liver stiffness measurement (vibration-controlled transient elastography/FibroScan). High risk: consider liver biopsy. Management: weight loss 7-10% (reduces steatohepatitis), pioglitazone or vitamin E for NASH without diabetes, GLP-1 RA (emerging evidence), and semaglutide."),
  np("NP-CAT","Pharmacology",4,"A patient starting carbamazepine should be screened for HLA-B*1502 if they are of which ethnic background?",["Northern European descent","Southeast Asian descent (risk of Stevens-Johnson syndrome/toxic epidermal necrolysis)","African descent only","No screening is needed for any population"],1,"HLA-B*1502 screening before carbamazepine: mandatory for patients of Southeast Asian descent (Chinese, Filipino, Malaysian, Thai, Vietnamese, Indian). Positive HLA-B*1502: contraindication to carbamazepine (and possibly oxcarbazepine). 5-8% allele frequency in these populations. SJS/TEN risk: 5% in carriers vs. < 0.01% in non-carriers."),
  np("AANP","Mental Health",3,"A patient with treatment-resistant depression who has failed two adequate SSRI trials should be considered for:",["Continuing the same SSRI indefinitely","Augmentation strategies (lithium, atypical antipsychotic, or thyroid hormone), switching to a different class, or referral for TMS/ECT","No additional treatment options exist","Benzodiazepines as primary treatment"],1,"TRD management: switch antidepressant class (SNRI, bupropion, mirtazapine), augmentation (lithium, aripiprazole, quetiapine, thyroid hormone T3), combination antidepressants, or neuromodulation (TMS, ECT for severe/refractory). Esketamine (intranasal, Spravato) FDA-approved for TRD. ECT remains the most effective treatment for severe TRD."),
  np("AANP","Dermatology",3,"A patient with a suspicious pigmented lesion should have it evaluated using the ABCDE criteria. The D stands for:",["Density","Diameter greater than 6mm (pencil eraser size)","Depth","Duration"],1,"ABCDE of melanoma: Asymmetry, Border irregularity, Color variation (multiple colors/shades), Diameter > 6mm, and Evolving (changing in size, shape, color). Any concerning lesion requires excisional biopsy (NOT shave biopsy for suspected melanoma). Breslow thickness on pathology determines staging and management."),
  np("AANP","Musculoskeletal",3,"A patient with suspected carpal tunnel syndrome should have the diagnosis confirmed with:",["X-ray of the wrist","Nerve conduction studies and electromyography (NCS/EMG)","MRI of the wrist","Blood tests"],1,"NCS/EMG is the gold standard for CTS diagnosis: shows slowed median nerve conduction across the carpal tunnel and sensory/motor latency prolongation. Clinical tests (Phalen, Tinel) have moderate sensitivity. Ultrasound (median nerve CSA > 10mm2) is an emerging alternative. Treatment: wrist splinting (neutral position), corticosteroid injection, or surgical release."),
  np("NP-CAT","Infectious Disease",4,"A patient with infective endocarditis and positive blood cultures for Staphylococcus aureus should have treatment duration of:",["7 days of antibiotics","4-6 weeks of IV antibiotics based on valve type (native vs. prosthetic)","2 weeks of oral antibiotics","No specific duration guideline exists"],1,"IE treatment duration: native valve S. aureus: 4-6 weeks IV (nafcillin or oxacillin for MSSA, vancomycin or daptomycin for MRSA). Prosthetic valve: >= 6 weeks with combination therapy. Right-sided native valve IE in IVDU: may use abbreviated 2-week course (MSSA only). Surgical evaluation for: heart failure, uncontrolled infection, large vegetations, or prosthetic valve IE."),
  np("AANP","Reproductive",3,"A patient with PCOS should be screened for which metabolic comorbidities?",["No screening needed","Insulin resistance (glucose tolerance test), dyslipidemia, and depression","Only thyroid disease","Only hypertension"],1,"PCOS metabolic screening: OGTT or fasting glucose/HbA1c (insulin resistance in 50-70%), lipid panel (dyslipidemia), blood pressure, depression screening (PHQ-9), and OSA assessment. Lifestyle modification (weight loss 5-10%) improves all features. Metformin for insulin resistance. Combined OCP for menstrual regulation and hyperandrogenism."),
  np("AANP","Geriatrics",3,"The NP prescribing medications to an elderly patient should consult which resource to identify potentially inappropriate medications?",["Only the drug formulary","The AGS Beers Criteria (list of potentially inappropriate medications for older adults)","The Physician's Desk Reference only","No specific resource exists"],1,"AGS Beers Criteria: evidence-based list of medications that are potentially inappropriate for older adults (>= 65). Categories: avoid (regardless of condition), avoid in specific conditions, use with caution, and drug-drug interactions. Common Beers list medications: benzodiazepines, anticholinergics, NSAIDs (long-term), first-generation antihistamines, and meperidine."),
  np("NP-CAT","Hematological",4,"A patient on warfarin with a target INR of 2.5 has an INR of 3.8 without bleeding. The NP should:",["Administer IV vitamin K immediately","Hold warfarin for 1-2 doses and recheck INR, resume at a reduced dose","Continue the same warfarin dose","Double the warfarin dose"],1,"INR management without bleeding: INR 3.0-4.5: hold 1-2 doses, reduce weekly dose by 10-15%, recheck in 3-7 days. INR 4.5-10 without bleeding: hold warfarin, consider low-dose oral vitamin K (1-2.5mg) for high-risk patients. INR > 10 without bleeding: hold warfarin, give oral vitamin K 2.5-5mg, recheck next day."),
  np("AANP","Renal",3,"A patient with newly diagnosed CKD stage 3 (GFR 30-59 mL/min) should have the NP initiate:",["No treatment until dialysis is needed","ACEi or ARB for blood pressure control and proteinuria reduction, SGLT2 inhibitor, and dietary counseling","Only dietary sodium restriction","Erythropoietin therapy immediately"],1,"CKD stage 3 management: ACEi/ARB (reduce proteinuria and slow progression), SGLT2 inhibitor (CREDENCE, DAPA-CKD trials showed renal and cardiovascular benefit), BP target < 130/80, dietary counseling (sodium, potassium, phosphorus restriction), finerenone (FIDELIO-DKD for diabetic CKD), and monitor labs (creatinine, potassium, HCO3, CBC, calcium, phosphorus, PTH)."),
  np("AANP","Women's Health",3,"A patient with heavy menstrual bleeding should have the NP first evaluate:",["Prescribe hormonal treatment without evaluation","Obtain CBC, TSH, pregnancy test, and pelvic ultrasound to identify the cause before treatment","Refer for hysterectomy immediately","Reassure and schedule follow-up in 6 months"],1,"HMB evaluation: CBC (anemia assessment), pregnancy test (rule out pregnancy-related causes), TSH (thyroid dysfunction), coagulation studies (if adolescent or history of bleeding), and pelvic ultrasound (structural causes: fibroids, polyps, adenomyosis). Endometrial biopsy for age >= 45 or risk factors for endometrial cancer."),
  np("AANP","Preventive Medicine",2,"The NP should recommend colorectal cancer screening beginning at age:",["50 for all patients","45 for average-risk patients (USPSTF 2021 update)","40 for all patients","55 for average-risk patients"],1,"USPSTF 2021: CRC screening starting at age 45 (lowered from 50) for average-risk adults. Options: stool-based (FIT annually, FIT-DNA every 1-3 years) or direct visualization (colonoscopy every 10 years, CT colonography every 5 years, flexible sigmoidoscopy every 5 years). Earlier screening for high-risk (family history, IBD, Lynch syndrome)."),
  np("AANP","Cardiovascular",3,"A patient presenting with typical anginal chest pain and intermediate pretest probability should undergo:",["No further testing","Stress testing (exercise or pharmacological) to evaluate for coronary artery disease","Immediate cardiac catheterization","Only serial troponins"],1,"Intermediate pretest probability: stress testing is appropriate. Exercise stress test preferred if patient can exercise and has interpretable baseline ECG. Pharmacological stress (dobutamine or vasodilator) if cannot exercise. Add imaging (echo or nuclear) if baseline ECG is abnormal (LVH, digoxin, BBB). High pretest probability: consider direct catheterization."),
  np("AANP","Respiratory",3,"A patient with persistent cough for 8 weeks should have the NP consider the three most common causes:",["Pneumonia, bronchitis, and TB","Upper airway cough syndrome (post-nasal drip), asthma, and GERD","Lung cancer, PE, and heart failure","Bronchiectasis, ILD, and sarcoidosis"],1,"Chronic cough (> 8 weeks) most common causes: upper airway cough syndrome/PNDS (empiric trial of antihistamine/decongestant), cough-variant asthma (empiric inhaled corticosteroid), and GERD (empiric PPI). Evaluate sequentially or simultaneously. If on ACEi, switch to ARB. CXR should be obtained. If refractory, consider bronchoscopy, CT, or speech pathology evaluation."),
  np("NP-CAT","Neurological",4,"A patient with suspected multiple sclerosis should have diagnosis confirmed with:",["CT scan of the brain","MRI of the brain and spinal cord showing dissemination in space and time (McDonald criteria)","Lumbar puncture alone","EEG"],1,"MS diagnosis (McDonald criteria 2017): dissemination in space (lesions in >= 2 characteristic CNS regions) and time (simultaneous gadolinium-enhancing and non-enhancing lesions, or new lesion on follow-up MRI). Supportive: CSF oligoclonal bands, elevated IgG index. MRI is the most important diagnostic tool. Brain + spinal cord MRI recommended."),
  np("AANP","Endocrine",3,"A patient with subclinical hyperthyroidism (suppressed TSH, normal free T4 and T3) should be treated when:",["Always, regardless of TSH level","TSH is persistently < 0.1 mIU/L (fully suppressed) especially in patients age > 65, with heart disease, or osteoporosis","Never treated","Only if symptomatic"],1,"Subclinical hyperthyroidism treatment: TSH < 0.1 (grade 2): treat if age > 65 (atrial fibrillation risk), heart disease, osteoporosis, or symptomatic. TSH 0.1-0.4 (grade 1): observe in most cases, treat if > 65 with comorbidities. Treatment: radioactive iodine, antithyroid drugs, or surgery depending on cause (Graves vs. nodular)."),
  np("AANP","Gastrointestinal",3,"A patient with persistent dyspepsia who is H. pylori negative and has alarm features should have:",["Continued empiric PPI therapy","Upper endoscopy (EGD) to evaluate for malignancy or other structural disease","Only dietary modifications","Repeat H. pylori testing"],1,"Dyspepsia alarm features requiring EGD: unintended weight loss, progressive dysphagia, persistent vomiting, GI bleeding (anemia, melena, hematemesis), palpable abdominal mass, and age > 60 with new-onset dyspepsia. EGD evaluates for gastric/esophageal cancer, PUD, and other structural causes."),
  np("AANP","Mental Health",3,"A patient with social anxiety disorder should be offered:",["Benzodiazepines as first-line","CBT (cognitive behavioral therapy) and/or SSRI as first-line treatment","Only relaxation techniques","Stimulant medications"],1,"Social anxiety disorder first-line: CBT (exposure-based, cognitive restructuring) and/or SSRI (sertraline, paroxetine, fluvoxamine). SNRI venlafaxine is also effective. Combination CBT + SSRI may be optimal. Beta-blockers (propranolol) for performance-only anxiety (before public speaking). Benzodiazepines are second-line due to dependence risk."),
  np("AANP","Dermatology",3,"A patient with atopic dermatitis refractory to topical corticosteroids should be considered for:",["Oral corticosteroids long-term","Dupilumab (IL-4/IL-13 inhibitor) or JAK inhibitors as systemic therapy","No additional treatment options exist","Only phototherapy"],1,"Moderate-severe AD refractory to topicals: dupilumab (FDA-approved biologic, SC every 2 weeks, excellent safety profile), JAK inhibitors (abrocitinib, upadacitinib - oral), or traditional immunosuppressants (cyclosporine, methotrexate, mycophenolate). Phototherapy (narrowband UVB) is also effective. Avoid systemic corticosteroids long-term."),
  np("AANP","Musculoskeletal",3,"A patient with acute gout should receive which first-line treatment?",["Allopurinol during the acute attack","NSAIDs, colchicine, or corticosteroids (not urate-lowering therapy during the acute flare)","Aspirin","Probenecid"],1,"Acute gout first-line: NSAIDs (indomethacin, naproxen), colchicine (most effective within 24 hours of onset, low-dose regimen: 1.2mg then 0.6mg 1 hour later), or corticosteroids (oral, IA, or IM). Do NOT start or change urate-lowering therapy during an acute flare (can worsen or prolong the attack). If already on ULT, continue."),
  np("NP-CAT","Infectious Disease",3,"A patient with recurrent UTIs (> 2 in 6 months or > 3 in 12 months) should be managed with:",["Long-term full-dose antibiotics","Behavioral modifications and possibly low-dose prophylactic antibiotics or post-coital prophylaxis","No preventive measures exist","Surgical evaluation for all patients"],1,"Recurrent UTI prevention: behavioral (adequate hydration, void after intercourse, avoid spermicides), cranberry products (modest benefit), vaginal estrogen for postmenopausal women, and antibiotic prophylaxis (low-dose: nitrofurantoin, TMP-SMX, or cephalexin nightly or post-coital). Self-start therapy for select patients. Evaluate for underlying causes if atypical."),
  np("AANP","Reproductive",3,"A patient presenting with secondary amenorrhea should have the NP first rule out:",["Thyroid disease","Pregnancy (most common cause of secondary amenorrhea)","Premature ovarian failure","Pituitary tumor"],1,"Secondary amenorrhea workup: pregnancy test FIRST (most common cause). Then: TSH (thyroid disease), prolactin (prolactinoma), FSH (premature ovarian failure if elevated). If all normal: progesterone challenge test (withdrawal bleed indicates anovulation with adequate estrogen; no bleed suggests outflow tract obstruction or low estrogen). Assess BMI, stress, exercise."),
  np("AANP","Geriatrics",3,"Delirium in a hospitalized elderly patient is differentiated from dementia by:",["Gradual onset over months","Acute onset with fluctuating course, inattention, and often a reversible cause","Irreversible progressive decline","No difference exists"],1,"Delirium: acute onset (hours to days), fluctuating course, inattention (cardinal feature), altered level of consciousness, often reversible. Dementia: gradual onset (months to years), progressive, attention preserved early, clear sensorium. Delirium can be superimposed on dementia. Always look for underlying cause: infection, medications, metabolic derangements, pain, urinary retention."),
  np("AANP","Cardiovascular",3,"A patient with newly diagnosed heart failure should have which initial workup?",["Only a chest X-ray","ECG, echocardiogram, BNP/NT-proBNP, CBC, BMP, LFTs, TSH, lipid panel, and iron studies","Only BNP testing","Cardiac catheterization for all patients"],1,"New HF workup: ECG (arrhythmias, ischemia, LVH), echocardiogram (EF, valvular disease, diastolic function), BNP/NT-proBNP (diagnosis and prognosis), CBC (anemia), BMP (renal function, electrolytes), LFTs, TSH (thyroid-mediated cardiomyopathy), lipid panel, iron studies (iron deficiency is common and treatable), and consider ischemic evaluation."),
  np("AANP","Respiratory",3,"A patient with COPD should have spirometry performed to confirm diagnosis. The key finding is:",["Reduced FVC only","FEV1/FVC ratio less than 0.70 after bronchodilator administration","Normal spirometry","Increased FEV1"],1,"COPD diagnosis: post-bronchodilator FEV1/FVC < 0.70 confirms persistent airflow limitation. GOLD classification by FEV1: GOLD 1 (mild, >= 80%), GOLD 2 (moderate, 50-79%), GOLD 3 (severe, 30-49%), GOLD 4 (very severe, < 30%). Combined assessment uses symptoms (mMRC/CAT) and exacerbation history for treatment decisions."),
  np("AANP","Endocrine",3,"A patient with type 2 diabetes and established cardiovascular disease should have which medication prioritized?",["Sulfonylurea","GLP-1 receptor agonist or SGLT2 inhibitor (proven cardiovascular benefit independent of glycemic control)","DPP-4 inhibitor","Thiazolidinedione"],1,"ADA/EASD consensus: established ASCVD: GLP-1 RA (liraglutide, semaglutide, dulaglutide - LEADER, SUSTAIN-6, REWIND trials) or SGLT2i (empagliflozin, canagliflozin - EMPA-REG, CANVAS). Established HF or CKD: SGLT2i preferred (DAPA-HF, EMPEROR trials). These agents have CV/renal benefit INDEPENDENT of glucose lowering."),
  np("NP-CAT","Gastrointestinal",4,"A patient with Barrett esophagus with high-grade dysplasia should be managed with:",["Continued surveillance only","Endoscopic eradication therapy (radiofrequency ablation or endoscopic mucosal resection)","Immediate esophagectomy for all patients","Only high-dose PPI therapy"],1,"Barrett with HGD: endoscopic eradication therapy (RFA for flat dysplasia, EMR for visible lesions, then RFA for remaining Barrett). Success rate > 90% for eradicating dysplasia. Esophagectomy reserved for refractory cases or T1b adenocarcinoma. Follow-up: surveillance biopsies every 3 months for 1 year, then annually. PPI therapy continues."),
  np("AANP","Mental Health",3,"A patient with persistent depressive disorder (dysthymia) differs from major depressive disorder in that:",["It is more severe but shorter duration","Symptoms are present for at least 2 years but may be less severe than MDD","It only affects older adults","No treatment is available"],1,"PDD (dysthymia): depressed mood most days for at least 2 years (1 year in children/adolescents) with at least 2 additional symptoms. Less severe but more chronic than MDD. Double depression: MDD superimposed on PDD. Treatment: SSRIs or SNRIs (similar to MDD), CBT or CBASP (cognitive behavioral analysis system of psychotherapy). Combination therapy most effective."),
  np("AANP","Dermatology",3,"A patient with suspected melanoma should have the lesion:",["Shave biopsied for convenience","Excisional biopsy with narrow margins (1-2mm) to obtain full histopathological assessment including Breslow thickness","Punch biopsy in the center only","Observed for 6 months before biopsy"],1,"Suspected melanoma: excisional biopsy (full-thickness, includes subcutaneous fat) with 1-3mm margins. Breslow thickness (depth of invasion) is the most important prognostic factor and determines wide local excision margins and sentinel lymph node biopsy indication. Shave biopsy is inadequate (may transect the lesion, preventing accurate thickness measurement)."),
  np("AANP","Musculoskeletal",3,"A patient with suspected osteoporosis should have bone density assessed with:",["Plain X-rays of the spine","Dual-energy X-ray absorptiometry (DEXA scan)","CT scan","MRI"],1,"DEXA scan: gold standard for osteoporosis diagnosis. Indications: all women >= 65, men >= 70, postmenopausal women < 65 with risk factors, and anyone with fragility fracture. T-score interpretation: >= -1.0 normal, -1.0 to -2.5 osteopenia, <= -2.5 osteoporosis. FRAX tool calculates 10-year fracture probability to guide treatment decisions."),
  np("NP-CAT","Infectious Disease",3,"A patient with community-acquired pneumonia should have severity assessed to determine the site of care using:",["Only clinical judgment","CURB-65 or PSI/PORT score to guide outpatient vs. inpatient management","Chest X-ray findings alone","WBC count alone"],1,"CAP severity tools: CURB-65 (Confusion, Uremia BUN > 20, RR >= 30, BP < 90/60, age >= 65): 0-1 outpatient, 2 consider short inpatient or close outpatient, 3-5 hospitalize. PSI/PORT: more comprehensive, classifies into 5 risk classes. Additional factors: hypoxemia, multilobar infiltrates, comorbidities, and social factors also influence disposition."),
  np("AANP","Reproductive",3,"A patient with menorrhagia and uterine fibroids who desires fertility preservation should be offered:",["Hysterectomy","Myomectomy (surgical removal of fibroids preserving the uterus)","Only oral contraceptives","No treatment until menopause"],1,"Myomectomy preserves the uterus and fertility potential. Options: hysteroscopic (submucosal fibroids), laparoscopic, or open (large or multiple fibroids). Medical management: GnRH agonists (shrink fibroids temporarily), tranexamic acid (reduces bleeding), hormonal IUD (reduces menstrual flow). UAE (uterine artery embolization) is an alternative but may affect fertility."),
  np("AANP","Cardiovascular",3,"A patient with peripheral arterial disease should have ankle-brachial index interpreted as:",["0.9-1.0 is abnormal","ABI < 0.9 indicates PAD; < 0.4 indicates severe/critical limb ischemia","ABI > 1.3 always indicates severe disease","ABI is not useful for PAD diagnosis"],1,"ABI interpretation: > 1.3: non-compressible (calcified) arteries (common in diabetes, ESRD), 1.0-1.3: normal, 0.9-1.0: borderline, < 0.9: PAD, 0.4-0.9: moderate PAD (claudication), < 0.4: severe PAD (rest pain, tissue loss, critical limb ischemia). Exercise ABI increases sensitivity for mild disease."),
  np("AANP","Respiratory",3,"A patient with an incidental solitary pulmonary nodule of 8mm on CT should be managed according to:",["Immediate surgical resection","Fleischner Society guidelines with follow-up CT based on size and risk factors","No follow-up needed","PET scan for all nodules"],1,"Fleischner Society guidelines for solid nodules: < 6mm: no follow-up (low risk), 6-8mm: follow-up CT at 6-12 months (low risk) or at 6-12 and 18-24 months (high risk), > 8mm: CT at 3 months, PET/CT, or tissue biopsy. Risk factors: smoking, upper lobe location, spiculated margins, FDG avidity, and larger size."),
  np("NP-CAT","Endocrine",4,"A patient with a 2cm thyroid nodule and fine needle aspiration showing Bethesda category III (atypia of undetermined significance) should be managed with:",["Immediate thyroidectomy","Molecular testing (Afirma GSC, ThyroSeq) or repeat FNA in 6-12 weeks","No follow-up needed","Radioactive iodine therapy"],1,"Bethesda III (AUS/FLUS): indeterminate, ~15-30% malignancy risk. Options: repeat FNA in 6-12 weeks, molecular testing (Afirma GEC: rule-out test, high NPV; ThyroSeq: rule-in test, high PPV), or diagnostic lobectomy. Molecular testing can reduce unnecessary surgeries. If molecular test is benign: follow-up clinically and with ultrasound."),
  np("AANP","Mental Health",3,"A patient with bipolar disorder type I should receive which mood stabilizer as first-line maintenance?",["SSRI monotherapy","Lithium (first-line mood stabilizer with best evidence for suicide prevention)","Benzodiazepines","Stimulant medications"],1,"Bipolar I maintenance: lithium (gold standard, only medication proven to reduce suicide risk in bipolar), valproate, lamotrigine (better for depressive episodes), quetiapine, or olanzapine. SSRI monotherapy is CONTRAINDICATED (can trigger mania). If antidepressant needed, always combine with mood stabilizer. Monitor lithium levels (0.6-1.2 mEq/L), renal, and thyroid function."),
  np("AANP","Dermatology",3,"A patient presenting with a non-healing ulcer on sun-exposed skin should be evaluated for:",["Contact dermatitis","Squamous cell carcinoma or basal cell carcinoma","Psoriasis","Eczema"],1,"Non-healing ulcers on sun-exposed skin raise concern for cutaneous malignancy: SCC (keratinized, firm, may be tender), BCC (pearly, telangiectatic, rolled borders). Any non-healing wound > 4-6 weeks should be biopsied. Risk factors: chronic UV exposure, fair skin, immunosuppression, prior radiation. BCC is more common; SCC has higher metastatic potential."),
  np("AANP","Musculoskeletal",3,"A patient with suspected rotator cuff tear should have initial evaluation with:",["CT scan","Physical examination (empty can test, drop arm test) and plain radiographs, followed by MRI if rotator cuff tear is suspected","Bone scan","Arthroscopy as initial test"],1,"Rotator cuff evaluation: history and physical exam (supraspinatus: empty can/Jobe test; infraspinatus: external rotation lag; subscapularis: lift-off/belly-press). Plain films: rule out fracture, superior migration of humeral head (massive RCT). MRI: gold standard for soft tissue (tear confirmation, size, retraction, muscle quality). Ultrasound is an alternative."),
  np("AANP","Geriatrics",3,"An elderly patient presenting with acute confusion should have the NP use which assessment tool?",["Mini-Mental State Examination alone","Confusion Assessment Method (CAM) to screen for delirium","PHQ-9","CAGE questionnaire"],1,"CAM (Confusion Assessment Method): validated bedside screening tool for delirium. Four features: (1) acute onset and fluctuating course, (2) inattention, (3) disorganized thinking, and (4) altered level of consciousness. Diagnosis requires features 1 AND 2 PLUS either 3 OR 4. Sensitivity 94-100%, specificity 90-95%. Widely used in clinical practice."),
  np("AANP","Cardiovascular",3,"A patient with suspected pulmonary embolism should have risk stratified using:",["Only D-dimer testing","Wells score to determine pretest probability, then D-dimer for low-probability or CTPA for moderate-high probability","Immediate CTPA for all patients","Chest X-ray alone"],1,"PE workup: Wells score determines pretest probability. Score <= 4 (low/moderate probability): check D-dimer (if negative, PE excluded; if positive, proceed to CTPA). Score > 4 (high probability): proceed directly to CTPA (skip D-dimer, as it will likely be positive regardless). V/Q scan alternative when CTPA is contraindicated (contrast allergy, CKD)."),
  np("AANP","Respiratory",3,"A patient with newly diagnosed sarcoidosis and bilateral hilar lymphadenopathy without symptoms requires:",["Immediate systemic corticosteroids","Observation with serial monitoring as many patients with stage I sarcoidosis have spontaneous remission","Methotrexate as first-line","Lung transplant evaluation"],1,"Sarcoidosis staging: Stage I (bilateral hilar lymphadenopathy only): > 50% spontaneous remission within 2 years. Observation appropriate. Treat if: progressive symptoms, declining pulmonary function, extrapulmonary involvement (cardiac, neurological, ocular). Stage II-IV have lower spontaneous remission rates. First-line treatment when needed: systemic corticosteroids."),
  np("AANP","Endocrine",3,"A patient with suspected Cushing syndrome should have initial screening with:",["Random cortisol level","24-hour urinary free cortisol, late-night salivary cortisol, or low-dose dexamethasone suppression test","ACTH stimulation test","MRI of the pituitary as first test"],1,"Cushing syndrome screening (need 2 positive tests): 24-hour urinary free cortisol (elevated), late-night salivary cortisol (loss of diurnal variation), or 1mg overnight DST (failure to suppress cortisol to < 1.8). After confirming hypercortisolism: ACTH level differentiates ACTH-dependent (pituitary, ectopic) from ACTH-independent (adrenal)."),
  np("AANP","Gastrointestinal",3,"A patient with suspected irritable bowel syndrome should meet which diagnostic criteria?",["Any abdominal pain warrants an IBS diagnosis","Rome IV criteria: recurrent abdominal pain at least 1 day per week for 3 months, associated with defecation, change in stool frequency, or change in stool form","Only alternating diarrhea and constipation","Weight loss and blood in stool"],1,"Rome IV IBS criteria: recurrent abdominal pain >= 1 day/week in the last 3 months (onset >= 6 months ago) associated with >= 2 of: related to defecation, change in stool frequency, change in stool form. Subtypes: IBS-D (diarrhea), IBS-C (constipation), IBS-M (mixed). Red flags requiring further workup: weight loss, rectal bleeding, nocturnal symptoms, and family history of CRC/IBD."),
  np("NP-CAT","Pharmacology",3,"A patient starting statin therapy should have a baseline lipid panel and which other labs?",["Only LDL cholesterol","LFTs (AST/ALT) and fasting glucose/HbA1c (statins may increase diabetes risk)","Complete metabolic panel weekly","No baseline labs needed"],1,"Pre-statin labs: lipid panel (baseline and 4-12 weeks after starting), ALT/AST (baseline; recheck only if symptoms of hepatotoxicity), fasting glucose/HbA1c (statins increase T2DM risk slightly, especially high-intensity statins). CK if symptomatic (myalgias). Routine CK monitoring is not recommended. No routine LFT monitoring needed after baseline."),
  np("AANP","Mental Health",3,"A patient with suspected ADHD in adulthood should have the NP:",["Prescribe stimulants without formal evaluation","Conduct a comprehensive evaluation including self-report scales, collateral history, and rule out other conditions mimicking ADHD","Diagnose based solely on self-report","Refer to psychiatry without initial evaluation"],1,"Adult ADHD evaluation: structured diagnostic interview, validated self-report scales (ASRS), collateral information (partner, family member), childhood history (symptoms must have been present before age 12), and differential diagnosis (anxiety, depression, sleep disorders, substance use, thyroid disease can mimic ADHD). Neuropsychological testing for complex cases."),
  np("AANP","Preventive Medicine",2,"The NP should recommend which immunization for adults over 65?",["Only influenza vaccine","High-dose or adjuvanted influenza vaccine, pneumococcal vaccine (PCV20 or PCV15+PPSV23), Shingrix (recombinant zoster), and Tdap if not previously given","No vaccinations are recommended after age 65","Only tetanus booster"],1,"Adults >= 65 immunizations: high-dose or adjuvanted influenza (annually, improved immunogenicity in elderly), PCV20 or PCV15 followed by PPSV23, Shingrix (2 doses, even if prior Zostavax), Tdap (if not previously received, then Td every 10 years), and COVID-19 updated vaccine. Review travel-specific and other risk-based vaccinations."),
  np("AANP","Cardiovascular",3,"A patient with aortic stenosis should avoid which medications?",["ACE inhibitors at low doses","Vasodilators in large doses (can cause severe hypotension due to fixed cardiac output)","Low-dose beta-blockers","Statins"],1,"Severe AS: fixed cardiac output cannot compensate for decreased afterload from vasodilators. Avoid: large-dose vasodilators (nitrates, ACEi/ARBs at high doses initially), excessive diuresis (preload-dependent). Use caution: anesthesia-related vasodilation. Medical management is limited; definitive treatment is valve replacement (SAVR or TAVR)."),
  np("NP-CAT","Respiratory",4,"A patient with acute exacerbation of idiopathic pulmonary fibrosis should be managed with:",["Increasing the antifibrotic dose","Supportive care and possibly high-dose corticosteroids (though evidence is limited); mortality exceeds 50%","Only supplemental oxygen","Broad-spectrum antibiotics as sole therapy"],1,"Acute IPF exacerbation: rapid deterioration (days to weeks) with new ground-glass opacities on HRCT. High mortality (> 50%). Management: supportive (oxygen, possibly mechanical ventilation, though prognosis is poor), high-dose IV methylprednisolone (limited evidence), rule out infection and PE, and consider palliative care. Many exacerbations are triggers for goals-of-care discussions."),
  np("AANP","Endocrine",3,"A patient with suspected primary hyperparathyroidism should have which labs ordered?",["Only calcium level","Serum calcium, PTH, phosphorus, 25-hydroxyvitamin D, and 24-hour urine calcium","TSH only","ACTH stimulation test"],1,"Primary hyperPTH labs: serum calcium (elevated), PTH (inappropriately normal or elevated for the calcium level), phosphorus (low or low-normal), 25-OH vitamin D (rule out vitamin D deficiency which can mask hyperPTH), 24-hour urine calcium (rule out familial hypocalciuric hypercalcemia if low), and creatinine (assess renal function). Imaging: parathyroid sestamibi scan and/or 4D CT for surgical planning."),
  np("AANP","Gastrointestinal",3,"A patient with suspected functional dyspepsia who is under 60 with no alarm features should be managed with:",["Immediate EGD","Test-and-treat strategy for H. pylori, or empiric PPI trial","CT scan of the abdomen","Surgical referral"],1,"Functional dyspepsia management (< 60, no alarm features): test-and-treat H. pylori (urea breath test or stool antigen). If negative or eradication does not resolve symptoms: empiric PPI trial (4-8 weeks). If PPI fails: consider TCA (amitriptyline 10-25mg) or prokinetic. EGD reserved for treatment failure, alarm features, or age > 60 with new symptoms."),
  np("AANP","Women's Health",3,"A patient with vulvovaginal candidiasis should be treated with:",["Oral antibiotics","Topical azole antifungal (miconazole, clotrimazole) or single-dose oral fluconazole","Topical corticosteroids alone","Metronidazole"],1,"VVC treatment: uncomplicated (sporadic, mild-moderate, C. albicans, immunocompetent): topical azole (1-7 day course) or oral fluconazole 150mg single dose. Complicated (recurrent >= 4/year, severe, non-albicans species, immunocompromised): longer initial therapy and maintenance fluconazole weekly for 6 months. Avoid azoles in pregnancy first trimester."),
  np("AANP","Cardiovascular",3,"A patient with lower extremity edema should have the NP differentiate between cardiac, hepatic, and renal causes by evaluating:",["Only leg circumference","JVP, hepatojugular reflux, BNP, albumin, urinalysis, and liver function tests","Chest X-ray alone","Only serum sodium"],1,"Edema differential: cardiac (JVD, S3, crackles, elevated BNP, CXR cardiomegaly), hepatic (ascites, jaundice, spider angiomata, low albumin, elevated LFTs), renal (proteinuria, elevated creatinine, hypoalbuminemia in nephrotic syndrome), venous insufficiency (varicosities, hemosiderin staining, ABI normal). Medication-related (CCBs, NSAIDs) is also common."),
  np("AANP","Preventive Medicine",2,"The NP should screen for abdominal aortic aneurysm with ultrasound in:",["All adults over age 50","Men aged 65-75 who have ever smoked (USPSTF recommendation)","Only patients with family history","Women over 65 routinely"],1,"USPSTF AAA screening: one-time abdominal ultrasound for men aged 65-75 who have EVER smoked. Selective screening for men 65-75 who never smoked. No recommendation for women who never smoked. Women who have smoked: insufficient evidence (AHA/ACC suggest selective screening). AAA >= 5.5cm: refer for surgical repair evaluation."),
];

async function main() {
  let inserted = 0;
  const batchSize = 50;
  for (let i = 0; i < QS.length; i += batchSize) {
    const batch = QS.slice(i, i + batchSize);
    const values: string[] = [];
    const params: any[] = [];
    let idx = 1;
    for (const q of batch) {
      values.push(`($${idx},$${idx+1},$${idx+2},$${idx+3},$${idx+4},$${idx+5}::jsonb,$${idx+6}::jsonb,$${idx+7},$${idx+8}::integer,$${idx+9},$${idx+10},$${idx+11})`);
      params.push(q.tier,q.exam,"multiple_choice","published",q.stem,JSON.stringify(q.options),JSON.stringify([q.correct]),q.rationale,q.diff,q.bs,"BOTH",hash(q.stem));
      idx += 12;
    }
    const sql = `INSERT INTO exam_questions (tier, exam, question_type, status, stem, options, correct_answer, rationale, difficulty, body_system, region_scope, stem_hash)
                 SELECT v.* FROM (VALUES ${values.join(",")}) AS v(tier,exam,question_type,status,stem,options,correct_answer,rationale,difficulty,body_system,region_scope,stem_hash)
                 WHERE NOT EXISTS (SELECT 1 FROM exam_questions e WHERE e.stem_hash = v.stem_hash)`;
    const result = await pool.query(sql, params);
    inserted += result.rowCount || 0;
  }
  console.log(`[Combined-B5] Inserted ${inserted}/${QS.length}`);
  const counts = await pool.query(`SELECT tier, count(*) as cnt FROM exam_questions WHERE status='published' GROUP BY tier ORDER BY tier`);
  counts.rows.forEach((r: any) => console.log(`  ${r.tier}: ${r.cnt}`));
  await pool.end();
}
main().catch(e => { console.error(e); process.exit(1); });
